import { useState, useEffect, createContext, useContext, useCallback, useMemo } from 'react';
import { CheckCircle, AlertCircle, Info, X } from 'lucide-react';

const ToastContext = createContext(undefined);

let toastId = 0;

export function ToastProvider({ children }) {
  const [toasts, setToasts] = useState([]);

  const addToast = useCallback((message, type = 'info', duration = 4000) => {
    const id = ++toastId;
    setToasts((prev) => [...prev, { id, message, type }]);
    if (duration > 0) {
      setTimeout(() => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
      }, duration);
    }
  }, []);

  const removeToast = useCallback((id) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  // If specific toast.success, toast.error, toast.info methods are still desired,
  // they would need to be re-implemented or the context value changed back to toastFn.

  return (
    <ToastContext.Provider value={addToast}>
      {children}
      <div className="fixed bottom-4 right-4 z-50 flex flex-col gap-2 max-w-sm">
        {toasts.map((toast) => (
          <Toast key={toast.id} {...toast} onClose={() => removeToast(toast.id)} />
        ))}
      </div>
    </ToastContext.Provider>
  );
}

export function useToast() {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error('useToast must be used within ToastProvider');
  return ctx;
}

const iconMap = {
  success: CheckCircle,
  error: AlertCircle,
  info: Info,
};

const colorMap = {
  success: 'border-green-500/30 bg-green-500/10 text-green-300',
  error: 'border-red-500/30 bg-red-500/10 text-red-300',
  info: 'border-violet-500/30 bg-violet-500/10 text-violet-300',
};

function Toast({ message, type, onClose }) {
  const [visible, setVisible] = useState(false);
  const Icon = iconMap[type] || Info;

  useEffect(() => {
    requestAnimationFrame(() => setVisible(true));
  }, []);

  return (
    <div
      className={`flex items-center gap-3 px-4 py-3 rounded-xl border backdrop-blur-xl shadow-lg transition-all duration-300 ${colorMap[type]} ${
        visible ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-8'
      }`}
    >
      <Icon className="w-4 h-4 shrink-0" />
      <p className="text-sm flex-1">{message}</p>
      <button onClick={onClose} className="shrink-0 hover:opacity-70 transition-opacity">
        <X className="w-3.5 h-3.5" />
      </button>
    </div>
  );
}

import { createContext, useContext, useState, useCallback } from 'react';

const ViewAsContext = createContext(undefined);

/**
 * ViewAs context — lets Super Admin simulate other roles/groups.
 *
 * viewAs modes:
 *   null      → normal (no simulation)
 *   'customer' → simulate logged-in customer
 *   'group_admin' → simulate admin of a specific fleet group
 *
 * When active, useAuth and useFleet read overrides from this context.
 */
export function ViewAsProvider({ children }) {
  const [viewAs, setViewAs] = useState(null);
  // viewAs shape: { role: 'customer'|'group_admin', fleetId?, fleetName?, fleetStatus? }

  const enterViewAs = useCallback((config) => {
    setViewAs(config);
  }, []);

  const exitViewAs = useCallback(() => {
    setViewAs(null);
  }, []);

  const isViewMode = viewAs !== null;

  return (
    <ViewAsContext.Provider
      value={{
        viewAs,
        isViewMode,
        enterViewAs,
        exitViewAs,
      }}
    >
      {children}
    </ViewAsContext.Provider>
  );
}

export function useViewAs() {
  const context = useContext(ViewAsContext);
  if (context === undefined) {
    throw new Error('useViewAs must be used within a ViewAsProvider');
  }
  return context;
}

import { createContext, useContext, useEffect, useState } from 'react';
import { supabase } from '../lib/supabase';
import { useViewAs } from './ViewAsContext';

const AuthContext = createContext(undefined);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    supabase.auth
      .getSession()
      .then(({ data: { session } }) => {
        setUser(session?.user ?? null);
        if (session?.user) {
          fetchProfile(session.user.id);
        } else {
          setLoading(false);
        }
      })
      .catch((err) => {
        console.warn('Auth session init failed:', err.message);
        setUser(null);
        setLoading(false);
      });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange(async (_event, session) => {
      setUser(session?.user ?? null);
      if (session?.user) {
        await fetchProfile(session.user.id);
      } else {
        setProfile(null);
        setLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  async function fetchProfile(userId) {
    try {
      const { data, error } = await supabase
        .from('bubatrent_booking_profiles')
        .select('*')
        .eq('id', userId)
        .single();
      if (error) throw error;
      setProfile(data);
    } catch (err) {
      console.error('Error fetching profile:', err);
      setProfile(null);
    } finally {
      setLoading(false);
    }
  }

  async function refreshProfile() {
    if (user?.id) await fetchProfile(user.id);
  }

  async function signUp(email, password, displayName, phone) {
    const { normalizePhone } = await import('../utils/phoneUtils');
    const normalizedPhone = normalizePhone(phone);

    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: { data: { display_name: displayName, phone: normalizedPhone } },
    });
    if (error) throw error;

    // Feature C: check if a manual customer profile exists with same phone
    if (data?.user?.id && normalizedPhone) {
      try {
        const { data: existing } = await supabase
          .from('bubatrent_booking_profiles')
          .select('id, phone, created_by_admin, is_verified')
          .eq('phone', normalizedPhone)
          .not('created_by_admin', 'is', null)
          .limit(2);

        if (existing && existing.length === 1) {
          // Link: update the manual profile's id to this auth user
          const manualProfile = existing[0];
          await supabase
            .from('bubatrent_booking_profiles')
            .update({
              id: data.user.id,
              email: email,
              display_name: displayName,
            })
            .eq('id', manualProfile.id);
          console.log('Linked signup to existing manual customer profile');
        } else if (existing && existing.length > 1) {
          console.warn(
            'Multiple manual profiles with same phone — admin needs to resolve duplicates'
          );
        }
      } catch (linkErr) {
        console.warn('Phone linking check failed (non-blocking):', linkErr.message);
      }
    }

    return data;
  }

  async function signIn(email, password) {
    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });
    if (error) throw error;
    return data;
  }

  async function resetPassword(email) {
    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: `${window.location.origin}/login`,
    });
    if (error) throw error;
  }

  async function signOut() {
    try {
      await supabase.auth.signOut();
    } catch (err) {
      console.error('Sign out error:', err);
    } finally {
      // Always clear local state even if API fails
      setUser(null);
      setProfile(null);
    }
  }

  const realIsAdmin = profile?.role === 'admin' || profile?.role === 'super_admin';
  const realIsSuperAdmin = profile?.role === 'super_admin';

  // ViewAs overrides
  let viewAsContext;
  try {
    viewAsContext = useViewAs();
  } catch {
    viewAsContext = { isViewMode: false, viewAs: null };
  }
  const { isViewMode, viewAs } = viewAsContext;

  let isAdmin = realIsAdmin;
  let isSuperAdmin = realIsSuperAdmin;

  if (isViewMode && viewAs) {
    if (viewAs.role === 'customer') {
      isAdmin = false;
      isSuperAdmin = false;
    } else if (viewAs.role === 'group_admin') {
      isAdmin = true;
      isSuperAdmin = false;
    }
  }

  return (
    <AuthContext.Provider
      value={{
        user,
        profile,
        loading,
        isAdmin,
        isSuperAdmin,
        realIsSuperAdmin,
        isVerified:
          profile?.is_verified === true &&
          (!profile?.licence_expiry || new Date(profile.licence_expiry) >= new Date()),
        signUp,
        signIn,
        signOut,
        resetPassword,
        refreshProfile,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import { useState, useEffect, useCallback, createContext, useContext } from 'react';
import { supabase } from '../lib/supabase';
import { useViewAs } from './ViewAsContext';

const FleetContext = createContext(undefined);

/**
 * Fleet context provider — wraps admin pages.
 * Fetches user's fleet memberships and manages the active fleet.
 * Respects ViewAs overrides for role simulation.
 */
export function FleetProvider({ userId, isSuperAdmin, children }) {
  const [fleets, setFleets] = useState([]);
  const [memberships, setMemberships] = useState([]);
  const [activeFleetId, setActiveFleetId] = useState(null);
  const [loading, setLoading] = useState(true);

  // ViewAs integration
  let viewAsContext;
  try {
    viewAsContext = useViewAs();
  } catch {
    viewAsContext = { isViewMode: false, viewAs: null };
  }
  const { isViewMode, viewAs } = viewAsContext;

  useEffect(() => {
    if (!userId) return;
    fetchFleetData();
  }, [userId, isSuperAdmin]);

  async function fetchFleetData() {
    setLoading(true);
    try {
      if (isSuperAdmin) {
        const { data: allFleets } = await supabase
          .from('bubatrent_booking_fleet_groups')
          .select('*')
          .order('name');
        setFleets(allFleets || []);
        const { data: mData } = await supabase
          .from('bubatrent_booking_fleet_memberships')
          .select('*, bubatrent_booking_fleet_groups(*)')
          .eq('user_id', userId);
        setMemberships(mData || []);
        if (mData?.length) setActiveFleetId(mData[0].fleet_group_id);
        else if (allFleets?.length) setActiveFleetId(allFleets[0].id);
      } else {
        const { data: mData } = await supabase
          .from('bubatrent_booking_fleet_memberships')
          .select('*, bubatrent_booking_fleet_groups(*)')
          .eq('user_id', userId);
        setMemberships(mData || []);
        const userFleets = (mData || [])
          .map((m) => m.bubatrent_booking_fleet_groups)
          .filter(Boolean);
        setFleets(userFleets);
        if (userFleets.length) setActiveFleetId(userFleets[0].id);
      }
    } catch (err) {
      console.error('Error fetching fleet data:', err);
    } finally {
      setLoading(false);
    }
  }

  const activeFleet = fleets.find((f) => f.id === activeFleetId) || null;

  // Governance status flags — respect ViewAs overrides
  let effectiveFleetId = activeFleetId;
  let groupStatus = activeFleet?.status || 'PENDING_VERIFICATION';
  let isSuperGroup = activeFleet?.is_super_group === true;

  if (isViewMode && viewAs?.role === 'group_admin') {
    effectiveFleetId = viewAs.fleetId || activeFleetId;
    groupStatus = viewAs.fleetStatus || 'VERIFIED';
    isSuperGroup = viewAs.isSuperGroup || false;
  }

  const isGroupVerified = groupStatus === 'VERIFIED';
  const isGroupSuspended = groupStatus === 'SUSPENDED';
  const canAccessSensitiveData = isGroupVerified && !isGroupSuspended;
  const canWrite = isGroupVerified && !isGroupSuspended;

  return (
    <FleetContext.Provider
      value={{
        fleets,
        memberships,
        activeFleetId: effectiveFleetId,
        activeFleet:
          isViewMode && viewAs?.role === 'group_admin'
            ? fleets.find((f) => f.id === viewAs.fleetId) || {
                ...activeFleet,
                status: viewAs.fleetStatus,
                is_super_group: viewAs.isSuperGroup,
              }
            : activeFleet,
        setActiveFleetId,
        loading,
        refetchFleets: fetchFleetData,
        // Governance
        groupStatus,
        isGroupVerified,
        isGroupSuspended,
        isSuperGroup,
        canAccessSensitiveData,
        canWrite,
      }}
    >
      {children}
    </FleetContext.Provider>
  );
}

export function useFleet() {
  const context = useContext(FleetContext);
  if (context === undefined) {
    throw new Error('useFleet must be used within a FleetProvider');
  }
  return context;
}

import { supabase } from './supabase';

/**
 * Wrap supabase.auth.getSession() with a hard timeout.
 * On Android Chrome, the silent JWT refresh can hang indefinitely —
 * this ensures we always resolve or reject within `timeoutMs`.
 */
export async function getSessionWithTimeout(timeoutMs = 8000) {
  try {
    const result = await Promise.race([
      supabase.auth.getSession(),
      new Promise((_, reject) =>
        setTimeout(
          () => reject(new Error('Auth timed out. Please refresh the page and try again.')),
          timeoutMs
        )
      ),
    ]);
    return { session: result?.data?.session ?? null, error: result?.error ?? null };
  } catch (err) {
    return { session: null, error: err };
  }
}

/**
 * Log an upload step to the database for remote debugging.
 * Fire-and-forget — never blocks the upload flow.
 * Uses a 3-second timeout on getSession() to avoid hanging on Android.
 */
async function logUploadStep(step, message, metadata = {}, accessToken = null) {
  try {
    let token = accessToken;
    if (!token) {
      const result = await Promise.race([
        supabase.auth.getSession(),
        new Promise((_, rej) => setTimeout(() => rej(new Error('log-timeout')), 3000)),
      ]);
      token = result?.data?.session?.access_token;
    }
    if (!token) return;

    // We still need the user_id for the log entry — derive from the session
    // If we only have a token (passed in), do a quick getUser or just get the session data
    let userId = null;
    if (accessToken) {
      // Token was passed in — try to get user id from current session cache
      // (this won't trigger a refresh since we already have a valid token)
      try {
        const {
          data: { session: cachedSession },
        } = await Promise.race([
          supabase.auth.getSession(),
          new Promise((_, rej) => setTimeout(() => rej(new Error('log-uid-timeout')), 2000)),
        ]);
        userId = cachedSession?.user?.id;
      } catch {
        // Can't get user_id — skip logging
        return;
      }
    } else {
      // We got the session from the getSession call above — re-extract user_id
      try {
        const result2 = await Promise.race([
          supabase.auth.getSession(),
          new Promise((_, rej) => setTimeout(() => rej(new Error('log-uid-timeout')), 2000)),
        ]);
        userId = result2?.data?.session?.user?.id;
      } catch {
        return;
      }
    }
    if (!userId) return;

    await supabase.from('bubatrent_booking_upload_logs').insert({
      user_id: userId,
      booking_id: metadata.booking_id || null,
      step,
      message,
      metadata: {
        ...metadata,
        browser: navigator.userAgent,
        timestamp: new Date().toISOString(),
      },
    });
  } catch {
    // Never let logging break the upload
  }
}

/**
 * Robust mobile-friendly upload function.
 * 1. Sends the File object directly via XHR — no FileReader or ArrayBuffer copy,
 *    so Android browsers don't freeze from doubled memory usage.
 * 2. Uses XMLHttpRequest for maximum compatibility and progress tracking.
 * 3. Explicitly uses x-upsert: false to avoid RLS deadlocks.
 * 4. Logs each step to bubatrent_booking_upload_logs for remote debugging.
 * 5. Warns users when files exceed 5MB (still allows up to 10MB max).
 * 6. Accepts an optional accessToken to skip getSession() entirely (Android fix).
 */
export async function uploadFileRobust(bucket, path, file, toast = null, accessToken = null) {
  // Extract booking_id from path if possible (e.g. receipts/{bookingId}/...)
  const bookingIdMatch = path.match(/(?:receipts|documents|uploads)\/([a-f0-9-]+)\//i);
  const booking_id = bookingIdMatch ? bookingIdMatch[1] : null;
  const logMeta = {
    bucket,
    path,
    booking_id,
    file_name: file.name,
    file_type: file.type,
    file_size: file.size,
  };

  return new Promise(async (resolve) => {
    try {
      if (toast) toast.info('Step 1: Preparing file...');
      logUploadStep(
        'preflight',
        `Starting upload: ${file.name} (${(file.size / 1024).toFixed(1)}KB)`,
        logMeta,
        accessToken
      );

      // 0. Pre-flight checks
      if (file.name.match(/\.(heic|heif)$/i) || file.type.match(/heic|heif/i)) {
        logUploadStep('error', 'HEIC format rejected', logMeta, accessToken);
        return resolve({
          data: null,
          error: new Error(
            'HEIC format not supported. Please change camera settings to JPEG or use a different file.'
          ),
        });
      }
      if (file.size > 10 * 1024 * 1024) {
        logUploadStep(
          'error',
          `File too large: ${(file.size / 1024 / 1024).toFixed(1)}MB`,
          logMeta,
          accessToken
        );
        return resolve({
          data: null,
          error: new Error(
            `File is too large (${(file.size / 1024 / 1024).toFixed(1)}MB). Max allowed size is 10MB.`
          ),
        });
      }

      // Get auth token — use provided token or fall back to getSessionWithTimeout
      let token = accessToken;
      if (!token) {
        const { session, error: sessionErr } = await getSessionWithTimeout(8000);
        if (sessionErr || !session) {
          logUploadStep('error', 'Not authenticated', {
            ...logMeta,
            sessionErr: sessionErr?.message,
          });
          return resolve({
            data: null,
            error: sessionErr || new Error('Not authenticated. Please log in again.'),
          });
        }
        token = session.access_token;
      }

      // Warn user about large files (> 5MB) — they still upload but may be slow on mobile
      if (file.size > 5 * 1024 * 1024 && toast) {
        toast.warn(
          `Large file (${(file.size / 1024 / 1024).toFixed(1)}MB) — upload may take a moment on mobile.`
        );
      }

      const kbSize = Math.round(file.size / 1024);
      if (toast) toast.info(`Step 2: Uploading ${kbSize}KB...`);
      logUploadStep(
        'uploading',
        `XHR upload starting: ${kbSize}KB to ${bucket}/${path}`,
        { ...logMeta, kbSize },
        accessToken
      );
      console.log(`[UploadHelper] Starting upload of ${kbSize}KB to ${bucket}/${path}`);

      // Determine MIME type — Android often returns file.type = "" for gallery images
      const mimeType = file.type || guessMimeFromName(file.name) || 'application/octet-stream';

      const url = `${import.meta.env.VITE_SUPABASE_URL}/storage/v1/object/${bucket}/${path}`;
      const xhr = new XMLHttpRequest();

      xhr.open('POST', url, true);
      xhr.setRequestHeader('Authorization', `Bearer ${token}`);
      xhr.setRequestHeader('apikey', import.meta.env.VITE_SUPABASE_ANON_KEY);
      xhr.setRequestHeader('Content-Type', mimeType);
      xhr.setRequestHeader('x-upsert', 'false'); // Critical: true causes RLS hangs on insert-only buckets

      xhr.timeout = 90000; // 90s timeout for slower mobile networks

      if (toast) {
        xhr.upload.onprogress = (e) => {
          if (e.lengthComputable) {
            const percent = Math.round((e.loaded / e.total) * 100);
            if (percent === 50 || percent === 100) {
              console.log(`[UploadHelper] Progress: ${percent}%`);
              if (percent === 50) {
                toast.info(`Uploading: 50%...`);
                logUploadStep('progress', 'Upload 50%', { ...logMeta, percent }, accessToken);
              }
            }
          }
        };
      }

      xhr.onload = () => {
        if (xhr.status >= 200 && xhr.status < 300) {
          console.log(`[UploadHelper] Upload success! HTTP ${xhr.status}`);
          logUploadStep(
            'success',
            `Upload complete! HTTP ${xhr.status}`,
            { ...logMeta, httpStatus: xhr.status },
            accessToken
          );
          resolve({ data: { path }, error: null });
        } else {
          console.error(`[UploadHelper] Upload error: HTTP ${xhr.status}`, xhr.responseText);
          let errMsg;
          try {
            const errBody = JSON.parse(xhr.responseText);
            errMsg = `Upload failed (HTTP ${xhr.status}): ${errBody.message || errBody.error}`;
          } catch {
            errMsg = `Upload failed (HTTP ${xhr.status}): ${xhr.statusText}`;
          }
          logUploadStep(
            'error',
            errMsg,
            { ...logMeta, httpStatus: xhr.status, response: xhr.responseText?.substring(0, 500) },
            accessToken
          );
          resolve({ data: null, error: new Error(errMsg) });
        }
      };

      xhr.onerror = () => {
        console.error('[UploadHelper] XHR network error.');
        logUploadStep(
          'network_error',
          'XHR network error — connection lost or CORS issue',
          logMeta,
          accessToken
        );
        resolve({ data: null, error: new Error('Network error during upload. Check connection.') });
      };

      xhr.ontimeout = () => {
        console.error('[UploadHelper] XHR timeout after 90s.');
        logUploadStep('timeout', 'XHR timed out after 90 seconds', logMeta, accessToken);
        resolve({
          data: null,
          error: new Error('Upload timed out after 90s. Please check your network connection.'),
        });
      };

      // Send the File object directly — XHR streams it from disk without
      // loading the entire file into JS heap memory.  This is the key fix
      // for Android browsers where FileReader.readAsArrayBuffer() + Uint8Array
      // copy would double RAM usage and freeze the JS thread.
      xhr.send(file);
    } catch (err) {
      console.error('[UploadHelper] Unexpected error:', err);
      logUploadStep(
        'error',
        `Unexpected error: ${err.message}`,
        { ...logMeta, stack: err.stack?.substring(0, 500) },
        accessToken
      );
      resolve({ data: null, error: err });
    }
  });
}

/**
 * Guess MIME type from file extension.
 * Android gallery often returns file.type = "" — this provides a sensible fallback.
 */
function guessMimeFromName(name = '') {
  const ext = name.split('.').pop().toLowerCase();
  const map = {
    jpg: 'image/jpeg',
    jpeg: 'image/jpeg',
    png: 'image/png',
    webp: 'image/webp',
    pdf: 'application/pdf',
    gif: 'image/gif',
  };
  return map[ext] || null;
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate, useSearchParams, Link } from 'react-router-dom';
import { useCar, checkAvailability } from '../hooks/useCars';
import { useAuth } from '../hooks/useAuth';
import { AlertTriangle } from 'lucide-react';
import DateRangePicker from '../components/DateRangePicker';
import PriceCalculator from '../components/PriceCalculator';
import LoadingSpinner from '../components/LoadingSpinner';
import { calculatePrice, formatMYR } from '../utils/pricing';
import {
  ArrowLeft,
  Users,
  Fuel,
  Settings2,
  Calendar,
  MapPin,
  Shield,
  CheckCircle,
  Star,
  AlertCircle,
  Loader2,
} from 'lucide-react';

export default function CarDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { user, isVerified } = useAuth();
  const { car, loading, error } = useCar(id);
  const [pickupDate, setPickupDate] = useState(searchParams.get('pickup') || '');
  const [returnDate, setReturnDate] = useState(searchParams.get('return') || '');
  const [isAvailable, setIsAvailable] = useState(null);
  const [checkingAvailability, setCheckingAvailability] = useState(false);

  // Check availability when dates change
  useEffect(() => {
    if (!pickupDate || !returnDate || !id) {
      setIsAvailable(null);
      return;
    }
    let cancelled = false;
    async function doCheck() {
      try {
        setCheckingAvailability(true);
        const available = await checkAvailability(id, pickupDate, returnDate);
        if (!cancelled) setIsAvailable(available);
      } catch (err) {
        console.error('Availability check failed:', err);
        if (!cancelled) setIsAvailable(null);
      } finally {
        if (!cancelled) setCheckingAvailability(false);
      }
    }
    doCheck();
    return () => {
      cancelled = true;
    };
  }, [id, pickupDate, returnDate]);

  if (loading) return <LoadingSpinner fullScreen />;
  if (error || !car) {
    return (
      <div className="page-container text-center">
        <p className="text-red-400">Car not found</p>
        <Link to="/" className="text-violet-400 hover:underline mt-4 inline-block">
          Back to fleet
        </Link>
      </div>
    );
  }

  const { days, total, deposit } = calculatePrice(car.price_per_day, pickupDate, returnDate);

  function handleBookNow() {
    if (!pickupDate || !returnDate || days <= 0 || !isAvailable) return;
    const checkoutUrl = `/checkout/${car.id}?pickup=${pickupDate}&return=${returnDate}`;
    if (!user) {
      navigate(`/login?returnTo=${encodeURIComponent(checkoutUrl)}`);
      return;
    }
    navigate(checkoutUrl);
  }

  const features = car.features || [];

  return (
    <div className="page-container">
      <Link
        to="/"
        className="inline-flex items-center gap-1.5 text-sm text-slate-500 hover:text-white transition-colors mb-6"
      >
        <ArrowLeft className="w-4 h-4" />
        Back to fleet
      </Link>

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Left: Car Details */}
        <div className="flex-1 min-w-0">
          {/* Image */}
          <div className="rounded-2xl overflow-hidden mb-6 aspect-[16/9]">
            {car.image_url ? (
              <img
                src={car.image_url}
                alt={car.name}
                className="w-full h-full object-cover"
                loading="lazy"
                referrerPolicy="no-referrer"
              />
            ) : (
              <div className="w-full h-full bg-gradient-to-br from-dark-800 to-dark-900 flex items-center justify-center">
                <Calendar className="w-16 h-16 text-slate-700" />
              </div>
            )}
          </div>

          {/* Car Info */}
          <div className="glass-card mb-6">
            <div className="flex items-start justify-between gap-4 mb-4">
              <div>
                <h1 className="text-2xl sm:text-3xl font-bold text-white mb-2">{car.name}</h1>
                <div className="flex items-center gap-3">
                  <p className="text-slate-400">
                    {car.brand} {car.model} · {car.year}
                  </p>
                  {car.plate_number && (
                    <span className="text-xs font-mono px-2 py-0.5 rounded bg-white/5 text-slate-400 border border-white/10">
                      {car.plate_number}
                    </span>
                  )}
                </div>
              </div>
              <div className="text-right shrink-0">
                <p className="text-2xl font-bold gradient-text">{formatMYR(car.price_per_day)}</p>
                <p className="text-xs text-slate-500">per day</p>
              </div>
            </div>

            {/* Specs Grid */}
            <div className="grid grid-cols-3 gap-4 mb-6">
              {[
                { icon: Settings2, label: 'Transmission', value: car.transmission },
                { icon: Users, label: 'Seats', value: `${car.seats} seats` },
                { icon: Fuel, label: 'Fuel', value: car.fuel_type },
              ].map(({ icon: Icon, label, value }) => (
                <div key={label} className="glass-card !p-3 text-center">
                  <Icon className="w-5 h-5 text-violet-400 mx-auto mb-1" />
                  <p className="text-xs text-slate-500">{label}</p>
                  <p className="text-sm font-medium text-white capitalize">{value}</p>
                </div>
              ))}
            </div>

            {/* Features */}
            {features.length > 0 && (
              <div>
                <h3 className="text-sm font-semibold text-white mb-3">Features</h3>
                <div className="flex flex-wrap gap-2">
                  {features.map((feature) => (
                    <span
                      key={feature}
                      className="px-3 py-1.5 rounded-lg bg-white/5 border border-white/5 text-xs text-slate-300"
                    >
                      {feature}
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Trust Section */}
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            {[
              { icon: Shield, text: 'Fully Insured' },
              { icon: CheckCircle, text: 'Verified Vehicle' },
              { icon: Star, text: 'Premium Maintained' },
            ].map(({ icon: Icon, text }) => (
              <div key={text} className="flex items-center gap-2 glass-card !p-3">
                <Icon className="w-4 h-4 text-green-400 shrink-0" />
                <span className="text-xs text-slate-400">{text}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Right: Booking Panel (Sticky) */}
        <div className="lg:w-96 shrink-0">
          <div className="lg:sticky lg:top-24 space-y-4">
            <div className="glass-card glow-sm animate-pulse-glow">
              <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
                <MapPin className="w-5 h-5 text-violet-400" />
                Book This Car
              </h3>

              <DateRangePicker
                pickupDate={pickupDate}
                returnDate={returnDate}
                onPickupChange={setPickupDate}
                onReturnChange={setReturnDate}
                className="mb-4"
              />

              {/* Availability indicator */}
              {pickupDate && returnDate && days > 0 && (
                <div className="mb-4">
                  {checkingAvailability ? (
                    <div className="flex items-center gap-2 text-sm text-slate-400">
                      <Loader2 className="w-4 h-4 animate-spin" />
                      Checking availability...
                    </div>
                  ) : isAvailable === true ? (
                    <div className="flex items-center gap-2 text-sm text-green-400">
                      <CheckCircle className="w-4 h-4" />
                      Available for selected dates!
                    </div>
                  ) : isAvailable === false ? (
                    <div className="flex items-center gap-2 text-sm text-red-400">
                      <AlertCircle className="w-4 h-4" />
                      Not available for these dates. Try different dates.
                    </div>
                  ) : null}
                </div>
              )}

              {user && !isVerified ? (
                <div className="text-center">
                  <div className="flex items-center gap-2 justify-center text-sm text-yellow-400 mb-3">
                    <AlertTriangle className="w-4 h-4" />
                    Account not verified
                  </div>
                  <p className="text-xs text-slate-500 mb-3">
                    You need to verify your identity before booking.
                  </p>
                  <Link to="/verify" className="btn-primary w-full inline-block text-center">
                    Verify Now
                  </Link>
                </div>
              ) : (
                <>
                  <button
                    onClick={handleBookNow}
                    disabled={
                      !pickupDate ||
                      !returnDate ||
                      days <= 0 ||
                      checkingAvailability ||
                      isAvailable === false
                    }
                    className="btn-primary w-full !py-4 text-base"
                  >
                    {!user
                      ? 'Sign in to Book'
                      : checkingAvailability
                        ? 'Checking...'
                        : isAvailable === false
                          ? 'Not Available'
                          : days > 0
                            ? `Book Now · Pay ${formatMYR(deposit)} Deposit`
                            : 'Select Dates'}
                  </button>

                  {!user && (
                    <p className="text-xs text-slate-500 mt-2 text-center">
                      You need to sign in before booking.
                    </p>
                  )}
                </>
              )}
            </div>

            {days > 0 && (
              <PriceCalculator
                pricePerDay={car.price_per_day}
                pickupDate={pickupDate}
                returnDate={returnDate}
              />
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { useParams, useSearchParams, useNavigate, Link } from 'react-router-dom';
import { useCar } from '../hooks/useCars';
import { useAuth } from '../hooks/useAuth';
import { createHoldBooking, updateBookingCustomerInfo, cancelBooking } from '../hooks/useBookings';
import { supabase } from '../lib/supabase';
import { uploadFileRobust, getSessionWithTimeout } from '../lib/uploadHelper';
import BookingForm from '../components/BookingForm';
import LoadingSpinner from '../components/LoadingSpinner';
import { calculatePrice, formatMYR } from '../utils/pricing';
import { formatDate, formatTimeRemaining } from '../utils/dates';
import {
  ArrowLeft,
  Clock,
  CheckCircle,
  AlertTriangle,
  Shield,
  ChevronRight,
  FileCheck,
  Upload,
  FileImage,
  Loader2,
  Wallet,
  MessageCircle,
} from 'lucide-react';
import { useToast } from '../components/Toast';

const STEPS = ['Your Info', 'Review', 'Payment'];

export default function Checkout() {
  const { carId } = useParams();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { user, profile, isVerified, refreshProfile } = useAuth();
  const toast = useToast();
  const { car, loading: carLoading } = useCar(carId);

  const pickupDate = searchParams.get('pickup');
  const returnDate = searchParams.get('return');

  const [step, setStep] = useState(0);
  const [booking, setBooking] = useState(null);
  const [customerInfo, setCustomerInfo] = useState(null);
  const [holdError, setHoldError] = useState('');
  const [loading, setLoading] = useState(false);
  const [timeRemaining, setTimeRemaining] = useState('');
  const [receiptFile, setReceiptFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const timerRef = useRef(null);
  const holdCreatedRef = useRef(false);

  // 6-month advance booking limit
  const sixMonthsFromNow = new Date();
  sixMonthsFromNow.setMonth(sixMonthsFromNow.getMonth() + 6);
  const isTooFarAdvance = returnDate && new Date(returnDate) > sixMonthsFromNow;

  // Deposit credit
  const credit = Number(profile?.deposit_credit || 0);

  // Create hold on mount
  useEffect(() => {
    if (!car || !user || !pickupDate || !returnDate || booking || holdCreatedRef.current) return;
    if (isTooFarAdvance) return;
    holdCreatedRef.current = true;
    async function createHold() {
      try {
        setLoading(true);
        const { days, total, deposit } = calculatePrice(car.price_per_day, pickupDate, returnDate);
        const hold = await createHoldBooking(
          car.id,
          user.id,
          pickupDate,
          returnDate,
          total,
          deposit,
          car.fleet_group_id
        );
        setBooking(hold);
      } catch (err) {
        holdCreatedRef.current = false;
        setHoldError(
          err.message || 'Unable to hold this booking. The dates may no longer be available.'
        );
      } finally {
        setLoading(false);
      }
    }
    createHold();
  }, [car, user, pickupDate, returnDate]);

  // Timer for hold expiry
  useEffect(() => {
    if (!booking?.hold_expires_at) return;
    function tick() {
      const remaining = formatTimeRemaining(booking.hold_expires_at);
      setTimeRemaining(remaining);
      if (remaining === 'Expired') {
        clearInterval(timerRef.current);
        cancelBooking(booking.id).catch(() => {});
      }
    }
    tick();
    timerRef.current = setInterval(tick, 1000);
    return () => clearInterval(timerRef.current);
  }, [booking?.hold_expires_at, booking?.id]);

  if (carLoading || (loading && !holdError)) return <LoadingSpinner fullScreen />;

  if (!pickupDate || !returnDate || !car) {
    return (
      <div className="page-container text-center">
        <p className="text-red-400">Invalid checkout. Please select dates first.</p>
        <Link to="/" className="text-violet-400 hover:underline mt-4 inline-block">
          Back to fleet
        </Link>
      </div>
    );
  }

  // Block unverified users
  if (!isVerified) {
    return (
      <div className="page-container max-w-lg mx-auto text-center">
        <div className="glass-card">
          <div className="w-16 h-16 rounded-full bg-yellow-500/10 flex items-center justify-center mx-auto mb-4">
            <FileCheck className="w-8 h-8 text-yellow-400" />
          </div>
          <h2 className="text-xl font-semibold text-white mb-2">Verification Required</h2>
          <p className="text-sm text-slate-400 mb-6">
            You need to verify your identity before booking a car.
          </p>
          <Link to="/verify" className="btn-primary inline-flex items-center gap-2">
            Verify Now
          </Link>
        </div>
      </div>
    );
  }

  // Block too-far-advance bookings
  if (isTooFarAdvance) {
    return (
      <div className="page-container max-w-lg mx-auto text-center">
        <div className="glass-card">
          <div className="w-16 h-16 rounded-full bg-red-500/10 flex items-center justify-center mx-auto mb-4">
            <AlertTriangle className="w-8 h-8 text-red-400" />
          </div>
          <h2 className="text-xl font-semibold text-white mb-2">Booking Too Far in Advance</h2>
          <p className="text-sm text-slate-400 mb-6">
            You can only book up to 6 months in advance.
          </p>
          <Link to={`/cars/${carId}`} className="btn-primary inline-flex items-center gap-2">
            Change Dates
          </Link>
        </div>
      </div>
    );
  }

  if (holdError) {
    return (
      <div className="page-container max-w-lg mx-auto text-center">
        <div className="glass-card">
          <div className="w-16 h-16 rounded-full bg-red-500/10 flex items-center justify-center mx-auto mb-4">
            <AlertTriangle className="w-8 h-8 text-red-400" />
          </div>
          <h2 className="text-xl font-semibold text-white mb-2">Booking Unavailable</h2>
          <p className="text-sm text-slate-400 mb-6">{holdError}</p>
          <Link to={`/cars/${carId}`} className="btn-primary inline-flex items-center gap-2">
            Try Different Dates
          </Link>
        </div>
      </div>
    );
  }

  const { days, total, deposit } = calculatePrice(car.price_per_day, pickupDate, returnDate);
  const creditApplied = Math.min(credit, deposit);
  const amountDue = deposit - creditApplied;
  const isExpired = timeRemaining === 'Expired';

  async function handleInfoSubmit(info) {
    try {
      setLoading(true);
      await updateBookingCustomerInfo(booking.id, info);
      setCustomerInfo(info);
      setStep(1);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  }

  async function handleDepositPayment() {
    if (amountDue > 0 && !receiptFile) {
      toast.error('Please upload your payment receipt.');
      return;
    }
    // Get session once with timeout — avoids Android getSession() hang
    const { session, error: sessionErr } = await getSessionWithTimeout(8000);
    if (sessionErr || !session) {
      toast.error('Session expired. Please refresh the page and log in again.');
      return;
    }
    const token = session.access_token;

    setUploading(true);
    try {
      let receiptPath = null;

      // Upload receipt if payment is required
      if (receiptFile) {
        const ext =
          receiptFile.name
            .split('.')
            .pop()
            .replace(/[^a-zA-Z0-9]/g, '') || 'jpg';
        const path = `receipts/${booking.id}/deposit_${Date.now()}.${ext}`;
        const { error: upErr } = await uploadFileRobust(
          'customer-documents',
          path,
          receiptFile,
          toast,
          token
        );
        if (upErr) throw upErr;
        receiptPath = path;
      }

      // Update booking with deposit info
      const updateData = {
        status: 'DEPOSIT_PAID',
        deposit_status: amountDue > 0 ? 'uploaded' : 'verified', // Auto-verify if fully covered by credit
        deposit_receipt_path: receiptPath,
        credit_applied: creditApplied,
        hold_expires_at: null,
        full_payment_amount: total,
      };
      const { error: bookErr } = await supabase
        .from('bubatrent_booking_bookings')
        .update(updateData)
        .eq('id', booking.id);
      if (bookErr) throw bookErr;

      // Create payment record
      const { error: payErr } = await supabase.from('bubatrent_booking_payments').insert({
        booking_id: booking.id,
        amount: deposit,
        payment_method: 'bank_transfer',
        status: amountDue > 0 ? 'pending' : 'completed',
        simulated: false,
        payment_type: 'deposit',
        receipt_path: receiptPath,
        reference_number: `DEP-${Date.now().toString(36).toUpperCase()}`,
      });
      if (payErr) throw payErr;

      // Deduct credit if applied
      if (creditApplied > 0) {
        // Update profile credit
        const { error: creditErr } = await supabase
          .from('bubatrent_booking_profiles')
          .update({ deposit_credit: credit - creditApplied })
          .eq('id', user.id);
        if (creditErr) throw creditErr;

        // Create credit transaction record
        await supabase.from('bubatrent_booking_credit_transactions').insert({
          user_id: user.id,
          booking_id: booking.id,
          amount: -creditApplied,
          type: 'applied',
          description: `Credit applied to booking deposit`,
        });

        await refreshProfile();
      }

      navigate(`/booking/${booking.id}/confirmation`);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setUploading(false);
    }
  }

  return (
    <div className="page-container max-w-4xl mx-auto">
      <Link
        to={`/cars/${carId}`}
        className="inline-flex items-center gap-1.5 text-sm text-slate-500 hover:text-white transition-colors mb-6"
      >
        <ArrowLeft className="w-4 h-4" />
        Back to car
      </Link>

      {/* Hold Timer */}
      {booking && !isExpired && (
        <div className="glass-card !p-3 flex items-center justify-between mb-6 border-yellow-500/20">
          <div className="flex items-center gap-2 text-sm text-yellow-300">
            <Clock className="w-4 h-4" />
            <span>Booking held for you</span>
          </div>
          <span className="text-sm font-mono font-bold text-yellow-300">{timeRemaining}</span>
        </div>
      )}

      {isExpired && (
        <div className="glass-card !p-4 mb-6 border-red-500/20 text-center">
          <p className="text-red-400 font-medium">Your hold has expired. Please start over.</p>
          <Link
            to={`/cars/${carId}`}
            className="text-violet-400 hover:underline text-sm mt-2 inline-block"
          >
            Go back
          </Link>
        </div>
      )}

      {/* Step Indicator */}
      <div className="flex items-center justify-center gap-2 mb-8">
        {STEPS.map((s, i) => (
          <div key={s} className="flex items-center gap-2">
            <div
              className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium transition-all ${
                i === step
                  ? 'bg-violet-500/20 text-violet-300 border border-violet-500/30'
                  : i < step
                    ? 'bg-green-500/10 text-green-400'
                    : 'bg-white/5 text-slate-500'
              }`}
            >
              {i < step ? (
                <CheckCircle className="w-3.5 h-3.5" />
              ) : (
                <span className="w-4 text-center">{i + 1}</span>
              )}
              <span className="hidden sm:inline">{s}</span>
            </div>
            {i < STEPS.length - 1 && <ChevronRight className="w-4 h-4 text-slate-700" />}
          </div>
        ))}
      </div>

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Left: Current Step */}
        <div className="flex-1 min-w-0">
          {step === 0 && (
            <div className="glass-card animate-fade-in">
              <h2 className="text-lg font-semibold text-white mb-6">Your Information</h2>
              <BookingForm
                onSubmit={handleInfoSubmit}
                loading={loading}
                initialData={{
                  email: user?.email || '',
                  name: profile?.display_name || '',
                  phone: profile?.phone || '',
                }}
              />
            </div>
          )}

          {step === 1 && (
            <div className="glass-card animate-fade-in">
              <h2 className="text-lg font-semibold text-white mb-6">Review Your Booking</h2>
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-xs text-slate-500 mb-1">Name</p>
                    <p className="text-sm text-white">{customerInfo?.name}</p>
                  </div>
                  <div>
                    <p className="text-xs text-slate-500 mb-1">Email</p>
                    <p className="text-sm text-white">{customerInfo?.email}</p>
                  </div>
                  <div>
                    <p className="text-xs text-slate-500 mb-1">Phone</p>
                    <p className="text-sm text-white">{customerInfo?.phone}</p>
                  </div>
                </div>
                {customerInfo?.notes && (
                  <div>
                    <p className="text-xs text-slate-500 mb-1">Notes</p>
                    <p className="text-sm text-slate-300">{customerInfo.notes}</p>
                  </div>
                )}
                <div className="border-t border-white/5 pt-4 flex gap-3">
                  <button onClick={() => setStep(0)} className="btn-secondary flex-1">
                    Edit Info
                  </button>
                  <button
                    onClick={() => setStep(2)}
                    className="btn-primary flex-1"
                    disabled={isExpired}
                  >
                    Proceed to Payment
                  </button>
                </div>
              </div>
            </div>
          )}

          {step === 2 && (
            <div className="glass-card animate-fade-in">
              <h2 className="text-lg font-semibold text-white mb-2">Deposit Payment</h2>
              <p className="text-sm text-slate-400 mb-6">
                Upload your payment receipt to secure this booking. Full rental payment is due at
                pickup.
              </p>

              {/* Credit applied */}
              {creditApplied > 0 && (
                <div className="flex items-center gap-3 px-4 py-3 rounded-xl bg-green-500/10 border border-green-500/20 mb-4">
                  <Wallet className="w-5 h-5 text-green-400" />
                  <div>
                    <p className="text-sm text-green-300 font-medium">
                      Credit Applied: {formatMYR(creditApplied)}
                    </p>
                    <p className="text-xs text-green-400/70">Deducted from your deposit balance</p>
                  </div>
                </div>
              )}

              {/* Payment breakdown */}
              <div className="space-y-2 mb-6 text-sm">
                <div className="flex justify-between">
                  <span className="text-slate-400">Deposit Required</span>
                  <span className="text-white">{formatMYR(deposit)}</span>
                </div>
                {creditApplied > 0 && (
                  <div className="flex justify-between text-green-400">
                    <span>Credit Applied</span>
                    <span>-{formatMYR(creditApplied)}</span>
                  </div>
                )}
                <div className="flex justify-between border-t border-white/5 pt-2 font-semibold">
                  <span className="text-white">Amount Due</span>
                  <span className="text-violet-300">{formatMYR(amountDue)}</span>
                </div>
              </div>

              {/* Receipt upload (if payment needed) */}
              {amountDue > 0 ? (
                (() => {
                  const contactPhone =
                    car?.bubatrent_booking_fleet_groups?.support_whatsapp?.replace(/\D/g, '') ||
                    '60162569733';
                  const contactName =
                    car?.bubatrent_booking_fleet_groups?.name || 'Rent2Go Support';
                  const whatsappUrl = `https://wa.me/${contactPhone}?text=${encodeURIComponent(`Hi ${contactName}, I would like to pay the deposit of ${formatMYR(amountDue)} for booking ${car?.brand} ${car?.model}. Please provide the bank account details.`)}`;

                  return (
                    <>
                      <div className="text-xs text-slate-400 mb-4 bg-white/5 p-3 rounded-xl border border-white/10">
                        <span className="block mb-2 text-white font-medium">
                          Payment Instructions:
                        </span>
                        <ol className="list-decimal pl-4 space-y-1.5">
                          <li>
                            Please{' '}
                            <a
                              href={whatsappUrl}
                              target="_blank"
                              rel="noreferrer"
                              className="text-green-400 hover:text-green-300 hover:underline font-medium"
                            >
                              WhatsApp our admin
                            </a>{' '}
                            to get the bank account details.
                          </li>
                          <li>
                            Transfer{' '}
                            <span className="text-white font-semibold">{formatMYR(amountDue)}</span>{' '}
                            to the provided account.
                          </li>
                          <li>Upload your payment receipt below to secure your booking.</li>
                        </ol>
                      </div>

                      <a
                        href={whatsappUrl}
                        target="_blank"
                        rel="noreferrer"
                        className="flex items-center justify-center gap-2 w-full py-3.5 mb-6 bg-[#25D366] hover:bg-[#20BE5C] text-white rounded-xl font-medium transition-all shadow-lg hover:shadow-[#25D366]/30 hover:-translate-y-0.5"
                      >
