                  <strong className="text-white">{email}</strong>
                </p>
                <button
                  onClick={() => {
                    setForgotMode(false);
                    setResetSent(false);
                  }}
                  className="btn-secondary text-sm"
                >
                  <ArrowLeft className="w-4 h-4 inline mr-1" />
                  Back to Sign In
                </button>
              </div>
            ) : (
              <form onSubmit={handleForgotPassword} className="space-y-5">
                <div>
                  <label className="input-label flex items-center gap-1.5">
                    <Mail className="w-4 h-4 text-violet-400" />
                    Email
                  </label>
                  <input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="input-field"
                    placeholder="you@email.com"
                    required
                    disabled={loading}
                  />
                </div>

                <button type="submit" disabled={loading} className="btn-primary w-full">
                  {loading ? 'Sending...' : 'Send Reset Link'}
                </button>

                <button
                  type="button"
                  onClick={() => {
                    setForgotMode(false);
                    setError('');
                  }}
                  className="w-full text-center text-sm text-slate-500 hover:text-white transition-colors"
                >
                  <ArrowLeft className="w-3.5 h-3.5 inline mr-1" />
                  Back to Sign In
                </button>
              </form>
            )
          ) : (
            <>
              <form onSubmit={handleSubmit} className="space-y-5">
                <div>
                  <label className="input-label flex items-center gap-1.5">
                    <Mail className="w-4 h-4 text-violet-400" />
                    Email
                  </label>
                  <input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="input-field"
                    placeholder="you@email.com"
                    required
                    disabled={loading}
                  />
                </div>

                <div>
                  <div className="flex items-center justify-between mb-2">
                    <label className="input-label !mb-0 flex items-center gap-1.5">
                      <Lock className="w-4 h-4 text-violet-400" />
                      Password
                    </label>
                    <button
                      type="button"
                      onClick={() => {
                        setForgotMode(true);
                        setError('');
                      }}
                      className="text-xs text-violet-400 hover:text-violet-300 transition-colors"
                    >
                      Forgot password?
                    </button>
                  </div>
                  <div className="relative">
                    <input
                      type={showPassword ? 'text' : 'password'}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      className="input-field !pr-10"
                      placeholder="••••••••"
                      required
                      disabled={loading}
                      minLength={6}
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-slate-300 transition-colors"
                      tabIndex={-1}
                    >
                      {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                    </button>
                  </div>
                </div>

                {lockedUntil && (
                  <p className="text-xs text-yellow-400 text-center">
                    Account locked for {lockCountdown}s due to too many failed attempts
                  </p>
                )}

                <button
                  type="submit"
                  disabled={loading || !!lockedUntil}
                  className="btn-primary w-full"
                >
                  {loading
                    ? 'Signing in...'
                    : lockedUntil
                      ? `Locked (${lockCountdown}s)`
                      : 'Sign In'}
                </button>
              </form>

              <p className="text-center text-sm text-slate-500 mt-6">
                Don't have an account?{' '}
                <Link to="/signup" className="text-violet-400 hover:text-violet-300 font-medium">
                  Sign up
                </Link>
              </p>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

