import { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { supabase } from '../lib/supabase';
import { uploadFileRobust, getSessionWithTimeout } from '../lib/uploadHelper';
import { useToast } from '../components/Toast';
import {
  FileCheck,
  Shield,
  Upload,
  FileImage,
  Loader2,
  CheckCircle,
  AlertCircle,
  Phone,
  CreditCard,
  Clock,
  MapPin,
} from 'lucide-react';

export default function VerifyAccount() {
  const { user, profile, isVerified, refreshProfile } = useAuth();
  const toast = useToast();

  const licenceExpired =
    profile?.is_verified &&
    profile?.licence_expiry &&
    new Date(profile.licence_expiry) < new Date();
  const hasSubmittedDocs = profile?.ic_number && profile?.ic_file_path && !profile?.is_verified;

  const [icNumber, setIcNumber] = useState(profile?.ic_number || '');
  const [licenceExpiry, setLicenceExpiry] = useState(profile?.licence_expiry || '');
  const [phone, setPhone] = useState(profile?.phone || '');
  const [addressLine1, setAddressLine1] = useState(profile?.address_line1 || '');
  const [addressLine2, setAddressLine2] = useState(profile?.address_line2 || '');
  const [city, setCity] = useState(profile?.city || '');
  const [state, setState] = useState(profile?.state || '');
  const [postcode, setPostcode] = useState(profile?.postcode || '');
  const [icFile, setIcFile] = useState(null);
  const [licenceFile, setLicenceFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState('');
  const [submitted, setSubmitted] = useState(false);

  const MAX_FILE_SIZE = 5 * 1024 * 1024;
  const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'image/webp', 'application/pdf'];

  function validateFile(file, label) {
    if (!file) return `${label} image is required`;
    if (file.size > MAX_FILE_SIZE) return `${label} file exceeds 5MB limit`;
    if (!ALLOWED_TYPES.includes(file.type)) return `${label}: only JPG, PNG, WebP, or PDF allowed`;
    return null;
  }

  async function uploadFile(file, folder, token) {
    const ext =
      file.name
        .split('.')
        .pop()
        .replace(/[^a-zA-Z0-9]/g, '') || 'jpg';
    const filePath = `profiles/${user.id}/${folder}_${Date.now()}.${ext}`;
    const { error: uploadErr } = await uploadFileRobust(
      'customer-documents',
      filePath,
      file,
      toast,
      token
    );
    if (uploadErr) throw uploadErr;
    return filePath;
  }

  async function handleSubmit(e) {
    e.preventDefault();
    setError('');

    if (!icNumber.trim()) {
      setError('IC / MyKad number is required.');
      return;
    }
    if (!licenceExpiry) {
      setError('Driving licence expiry date is required.');
      return;
    }
    if (new Date(licenceExpiry) < new Date()) {
      setError('Your driving licence has expired. Please enter a valid expiry date.');
      return;
    }
    if (!phone.trim() || phone.replace(/\D/g, '').length < 9) {
      setError('Please enter a valid phone number.');
      return;
    }
    if (!addressLine1.trim()) {
      setError('Address line 1 is required.');
      return;
    }
    if (!city.trim()) {
      setError('City is required.');
      return;
    }
    if (!state.trim()) {
      setError('State is required.');
      return;
    }
    if (!postcode.trim()) {
      setError('Postcode is required.');
      return;
    }

    // For first-time verification, files are required
    const isUpdate = profile?.is_verified || hasSubmittedDocs;
    if (!isUpdate) {
      const icErr = validateFile(icFile, 'IC / MyKad');
      if (icErr) {
        setError(icErr);
        return;
      }
      const licErr = validateFile(licenceFile, 'Driving Licence');
      if (licErr) {
        setError(licErr);
        return;
      }
    }

    // Get session once with timeout — avoids Android getSession() hang
    const { session, error: sessionErr } = await getSessionWithTimeout(8000);
    if (sessionErr || !session) {
      setError('Session expired. Please refresh the page and log in again.');
      return;
    }
    const token = session.access_token;

    setUploading(true);
    try {
      let icPath = profile?.ic_file_path || null;
      let licencePath = profile?.licence_file_path || null;

      if (icFile) icPath = await uploadFile(icFile, 'ic', token);
      if (licenceFile) licencePath = await uploadFile(licenceFile, 'licence', token);

      if (isUpdate) {
        // Submit as pending verification update (old stays valid)
        const { error: insertErr } = await supabase
          .from('bubatrent_booking_verification_updates')
          .insert({
            user_id: user.id,
            ic_number: icNumber.trim(),
            licence_expiry: licenceExpiry,
            ic_file_path: icPath,
            licence_file_path: licencePath,
            phone: phone.trim(),
            address_line1: addressLine1.trim(),
            address_line2: addressLine2.trim(),
            city: city.trim(),
            state: state.trim(),
            postcode: postcode.trim(),
          });
        if (insertErr) throw insertErr;
      } else {
        // First-time: update profile directly (still needs admin approval)
        const { error: updateErr } = await supabase
          .from('bubatrent_booking_profiles')
          .update({
            ic_number: icNumber.trim(),
            licence_expiry: licenceExpiry,
            ic_file_path: icPath,
            licence_file_path: licencePath,
            phone: phone.trim(),
            address_line1: addressLine1.trim(),
            address_line2: addressLine2.trim(),
            city: city.trim(),
            state: state.trim(),
            postcode: postcode.trim(),
          })
          .eq('id', user.id);
        if (updateErr) throw updateErr;
      }

      await refreshProfile();
      setSubmitted(true);
      toast.success(
        isUpdate ? 'Verification update submitted!' : 'Documents submitted for verification!'
      );
    } catch (err) {
      setError(err.message || 'Upload failed. Please try again.');
    } finally {
      setUploading(false);
    }
  }

  // Already verified (and licence not expired)
  if (isVerified && !licenceExpired) {
    return (
      <div className="page-container max-w-xl mx-auto">
        <div className="glass-card text-center animate-fade-in">
          <div className="w-16 h-16 rounded-full bg-green-500/10 flex items-center justify-center mx-auto mb-4">
            <CheckCircle className="w-8 h-8 text-green-400" />
          </div>
          <h1 className="text-2xl font-bold text-white mb-2">Account Verified</h1>
          <p className="text-sm text-slate-400 mb-6">
            Your identity has been verified. You can now book cars.
          </p>
          <div className="flex gap-3 justify-center">
            <Link to="/" className="btn-primary inline-flex items-center gap-2">
              Browse Fleet
            </Link>
            <Link to="/profile" className="btn-secondary inline-flex items-center gap-2">
              View Profile
            </Link>
          </div>
        </div>
      </div>
    );
  }

  // Licence expired — must update
  if (licenceExpired) {
    return (
      <div className="page-container max-w-xl mx-auto">
        <div className="glass-card text-center animate-fade-in">
          <div className="w-16 h-16 rounded-full bg-red-500/10 flex items-center justify-center mx-auto mb-4">
            <AlertCircle className="w-8 h-8 text-red-400" />
          </div>
          <h1 className="text-2xl font-bold text-white mb-2">Licence Expired</h1>
          <p className="text-sm text-slate-400 mb-4">
            Your driving licence has expired. Please update your licence to continue booking.
          </p>
          <p className="text-xs text-slate-500 mb-6">
            Upload a new licence with a valid expiry date below.
          </p>
        </div>
        {renderForm()}
      </div>
    );
  }

  // Pending verification (docs submitted, waiting for admin)
  if (hasSubmittedDocs || submitted) {
    return (
      <div className="page-container max-w-xl mx-auto">
        <div className="glass-card text-center animate-fade-in">
          <div className="w-16 h-16 rounded-full bg-yellow-500/10 flex items-center justify-center mx-auto mb-4">
            <Clock className="w-8 h-8 text-yellow-400" />
          </div>
          <h1 className="text-2xl font-bold text-white mb-2">Verification Pending</h1>
          <p className="text-sm text-slate-400 mb-2">
            Your documents have been submitted and are being reviewed.
          </p>
          <p className="text-xs text-slate-500 mb-6">
            This usually takes less than 24 hours. You'll be able to book once verified.
          </p>
          <Link to="/" className="btn-secondary inline-flex items-center gap-2">
            Back to Home
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="page-container max-w-xl mx-auto">
      <div className="text-center mb-8">
        <div className="w-14 h-14 rounded-2xl bg-violet-500/10 flex items-center justify-center mx-auto mb-4">
          <FileCheck className="w-7 h-7 text-violet-400" />
        </div>
        <h1 className="text-2xl font-bold text-white mb-1">Verify Your Account</h1>
        <p className="text-sm text-slate-400">
          Submit your IC and driving licence to start booking
        </p>
      </div>
      {renderForm()}
    </div>
  );

  function renderForm() {
    return (
      <>
        <div className="glass-card !p-4 flex items-start gap-3 mb-6">
          <Shield className="w-5 h-5 text-green-400 shrink-0 mt-0.5" />
          <div className="text-xs text-slate-400 leading-relaxed">
            <p className="text-green-300 font-medium mb-1">Your documents are secure</p>
            <p>Files are stored in private encrypted storage, accessible only by our admin team.</p>
          </div>
        </div>

        <div className="glass-card">
          <form onSubmit={handleSubmit} className="space-y-5">
            {error && (
              <div className="flex items-center gap-2 px-4 py-3 rounded-xl bg-red-500/10 border border-red-500/20 text-sm text-red-400">
                <AlertCircle className="w-4 h-4 shrink-0" />
                {error}
              </div>
            )}

            {/* Phone */}
            <div>
              <label className="input-label flex items-center gap-1.5">
                <Phone className="w-4 h-4 text-violet-400" />
                Phone Number *
              </label>
              <input
                type="tel"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                className="input-field"
                placeholder="+60 12-345 6789"
                maxLength={20}
                disabled={uploading}
              />
            </div>

            {/* IC Section */}
            <div className="border-t border-white/5 pt-5">
              <p className="text-sm font-medium text-white mb-4 flex items-center gap-2">
                <CreditCard className="w-4 h-4 text-violet-400" />
                IC / MyKad
              </p>
              <div className="space-y-4">
                <div>
                  <label className="input-label">IC Number (MyKad) *</label>
                  <input
                    type="text"
                    value={icNumber}
                    onChange={(e) => setIcNumber(e.target.value)}
                    className="input-field"
                    placeholder="e.g. 990101-14-1234"
                    maxLength={30}
                    disabled={uploading}
                  />
                </div>
                <div>
                  <label className="input-label">Driving Licence Expiry Date *</label>
                  <input
                    type="date"
                    value={licenceExpiry}
                    onChange={(e) => setLicenceExpiry(e.target.value)}
                    className="input-field"
                    disabled={uploading}
                  />
                </div>
                <div>
                  <label className="input-label">IC / MyKad Image *</label>
                  <label className="flex items-center gap-3 px-4 py-6 rounded-xl border-2 border-dashed border-white/10 hover:border-violet-500/30 cursor-pointer transition-colors">
                    <FileImage className="w-6 h-6 text-slate-500" />
                    <div>
                      <p className="text-sm text-slate-300">
                        {icFile ? icFile.name : 'Click to upload IC photo'}
                      </p>
                      <p className="text-xs text-slate-500">JPG, PNG, WebP or PDF · Max 5MB</p>
                    </div>
                    <input
                      type="file"
                      accept="image/*,.pdf"
                      onChange={(e) => setIcFile(e.target.files[0])}
                      className="hidden"
                      disabled={uploading}
                    />
                  </label>
                </div>
                <div>
                  <label className="input-label">Driving Licence Image *</label>
                  <label className="flex items-center gap-3 px-4 py-6 rounded-xl border-2 border-dashed border-white/10 hover:border-violet-500/30 cursor-pointer transition-colors">
                    <FileImage className="w-6 h-6 text-slate-500" />
                    <div>
                      <p className="text-sm text-slate-300">
                        {licenceFile ? licenceFile.name : 'Click to upload licence photo'}
                      </p>
                      <p className="text-xs text-slate-500">JPG, PNG, WebP or PDF · Max 5MB</p>
                    </div>
                    <input
                      type="file"
                      accept="image/*,.pdf"
                      onChange={(e) => setLicenceFile(e.target.files[0])}
                      className="hidden"
                      disabled={uploading}
                    />
                  </label>
                </div>
              </div>
            </div>

            {/* Address Section */}
            <div className="border-t border-white/5 pt-5">
              <p className="text-sm font-medium text-white mb-4 flex items-center gap-2">
                <MapPin className="w-4 h-4 text-violet-400" />
                Address
              </p>
              <div className="space-y-4">
                <div>
                  <label className="input-label">Address Line 1 *</label>
                  <input
                    type="text"
                    value={addressLine1}
                    onChange={(e) => setAddressLine1(e.target.value)}
                    className="input-field"
                    placeholder="Street address"
                    disabled={uploading}
                  />
                </div>
                <div>
                  <label className="input-label">Address Line 2</label>
                  <input
                    type="text"
                    value={addressLine2}
                    onChange={(e) => setAddressLine2(e.target.value)}
                    className="input-field"
                    placeholder="Apartment, unit, etc. (optional)"
                    disabled={uploading}
                  />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="input-label">City *</label>
                    <input
                      type="text"
                      value={city}
                      onChange={(e) => setCity(e.target.value)}
                      className="input-field"
                      placeholder="City"
                      disabled={uploading}
                    />
                  </div>
                  <div>
                    <label className="input-label">State *</label>
                    <select
                      value={state}
                      onChange={(e) => setState(e.target.value)}
                      className="input-field"
                      disabled={uploading}
                    >
                      <option value="">Select state</option>
                      {[
                        'Johor',
                        'Kedah',
                        'Kelantan',
                        'Melaka',
                        'Negeri Sembilan',
                        'Pahang',
                        'Perak',
                        'Perlis',
                        'Pulau Pinang',
                        'Sabah',
                        'Sarawak',
                        'Selangor',
                        'Terengganu',
                        'W.P. Kuala Lumpur',
                        'W.P. Labuan',
                        'W.P. Putrajaya',
                      ].map((s) => (
                        <option key={s} value={s}>
                          {s}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
                <div className="w-1/2">
                  <label className="input-label">Postcode *</label>
                  <input
                    type="text"
                    value={postcode}
                    onChange={(e) => setPostcode(e.target.value)}
                    className="input-field"
                    placeholder="e.g. 50000"
                    maxLength={10}
                    disabled={uploading}
                  />
                </div>
              </div>
            </div>

            <button
              type="submit"
              disabled={uploading}
              className="btn-primary w-full flex items-center justify-center gap-2"
            >
              {uploading ? (
                <>
                  <Loader2 className="w-5 h-5 animate-spin" /> Uploading...
                </>
              ) : (
                <>
                  <Upload className="w-5 h-5" /> Submit for Verification
                </>
              )}
            </button>
          </form>
        </div>
      </>
    );
  }
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import AdminLayout from '../../components/AdminLayout';
import { useAuth } from '../../hooks/useAuth';
import { useFleet } from '../../hooks/useFleet';
import { supabase } from '../../lib/supabase';
import { uploadFileRobust } from '../../lib/uploadHelper';
import { useToast } from '../../components/Toast';
import { normalizePhone } from '../../utils/phoneUtils';
import LoadingSpinner from '../../components/LoadingSpinner';
import {
  Search,
  User,
  Car,
  CalendarDays,
  Wallet,
  FileImage,
  Loader2,
  ArrowLeft,
  Shield,
  Check,
  AlertTriangle,
} from 'lucide-react';

export default function AdminBookForCustomer() {
  const { user, isSuperAdmin } = useAuth();
  const { activeFleetId, activeFleet } = useFleet();
  const navigate = useNavigate();
  const toast = useToast();

  const [step, setStep] = useState(1); // 1=customer, 2=car, 3=dates, 4=confirm

  // Step 1: Customer
  const [custSearch, setCustSearch] = useState('');
  const [custResults, setCustResults] = useState([]);
  const [selectedCust, setSelectedCust] = useState(null);
  const [searching, setSearching] = useState(false);

  // Step 2: Car
  const [cars, setCars] = useState([]);
  const [selectedCar, setSelectedCar] = useState(null);
  const [carsLoading, setCarsLoading] = useState(false);

  // Step 3: Dates
  const [pickupDate, setPickupDate] = useState('');
  const [returnDate, setReturnDate] = useState('');
  const [dateError, setDateError] = useState('');
  const [existingBookings, setExistingBookings] = useState([]);
  const [loadingBookings, setLoadingBookings] = useState(false);

  // Step 4: Config
  const [depositAmount, setDepositAmount] = useState(100);
  const [initialStatus, setInitialStatus] = useState('CONFIRMED');
  const [depositReceipt, setDepositReceipt] = useState(null);
  const [creating, setCreating] = useState(false);

  // Search customers
  async function handleCustSearch(q) {
    setCustSearch(q);
    if (q.length < 2) {
      setCustResults([]);
      return;
    }
    setSearching(true);
    const { data, error } = await supabase
      .from('bubatrent_booking_profiles')
      .select('id, display_name, username, phone, ic_number, is_verified')
      .or(
        `display_name.ilike.%${q}%,phone.ilike.%${q}%,ic_number.ilike.%${q}%,username.ilike.%${q}%`
      )
      .limit(10);
    if (error) console.error('[BookForCustomer] Search error:', error);
    setCustResults(data || []);
    setSearching(false);
  }

  // Confirmed statuses that block dates (HOLD does NOT block)
  const BLOCKING_STATUSES = ['DEPOSIT_PAID', 'CONFIRMED', 'PICKUP'];

  // Fetch cars when step 2
  useEffect(() => {
    if (step === 2 && activeFleetId) {
      setCarsLoading(true);
      supabase
        .from('bubatrent_booking_cars')
        .select('*')
        .eq('fleet_group_id', activeFleetId)
        .eq('is_available', true)
        .order('name')
        .then(({ data }) => {
          setCars(data || []);
          setCarsLoading(false);
        });
    }
  }, [step, activeFleetId]);

  // Fetch existing bookings for selected car when entering Step 3
  useEffect(() => {
    if (step === 3 && selectedCar) {
      setLoadingBookings(true);
      supabase
        .from('bubatrent_booking_bookings')
        .select('id, pickup_date, return_date, status, customer_name')
        .eq('car_id', selectedCar.id)
        .in('status', [...BLOCKING_STATUSES, 'HOLD'])
        .gte('return_date', new Date().toISOString().split('T')[0])
        .order('pickup_date')
        .then(({ data }) => {
          setExistingBookings(data || []);
          setLoadingBookings(false);
        });
    }
  }, [step, selectedCar]);

  // Check if selected dates overlap with confirmed bookings
  function getOverlap() {
    if (!pickupDate || !returnDate) return null;
    return existingBookings.find(
      (b) =>
        BLOCKING_STATUSES.includes(b.status) &&
        b.pickup_date <= returnDate &&
        b.return_date >= pickupDate
    );
  }

  // Validate dates
  function validateDates() {
    if (!pickupDate || !returnDate) {
      setDateError('Dates are required');
      return false;
    }
    const pickup = new Date(pickupDate);
    const ret = new Date(returnDate);
    if (ret <= pickup) {
      setDateError('Return must be after pickup');
      return false;
    }
    const sixMonths = new Date();
    sixMonths.setMonth(sixMonths.getMonth() + 6);
    if (pickup > sixMonths) {
      setDateError('Pickup must be within 6 months');
      return false;
    }
    const overlap = getOverlap();
    if (overlap) {
      setDateError(
        `Dates overlap with a ${overlap.status} booking (${overlap.pickup_date} → ${overlap.return_date})`
      );
      return false;
    }
    setDateError('');
    return true;
  }

  // Calculate price
  function calcTotal() {
    if (!pickupDate || !returnDate || !selectedCar) return 0;
    const days = Math.ceil((new Date(returnDate) - new Date(pickupDate)) / (1000 * 60 * 60 * 24));
    return days * (selectedCar.price_per_day || 0);
  }

  async function handleCreate() {
    if (!validateDates()) return;
    if (depositAmount < 100) {
      toast.error('Minimum deposit is RM100');
      return;
    }
    setCreating(true);

    try {
      // Overlap check — only block for confirmed statuses, not HOLD
      const { data: overlapping } = await supabase
        .from('bubatrent_booking_bookings')
        .select('id')
        .eq('car_id', selectedCar.id)
        .in('status', BLOCKING_STATUSES)
        .lte('pickup_date', returnDate)
        .gte('return_date', pickupDate)
        .limit(1);
      if (overlapping?.length > 0) {
        toast.error('Date overlap with a confirmed booking');
        setCreating(false);
        return;
      }

      const totalPrice = calcTotal();

      // Upload deposit receipt if provided
      let receiptUrl = null;
      if (depositReceipt) {
        const rPath = `receipts/admin_${Date.now()}.${depositReceipt.name.split('.').pop()}`;
        const { error: upErr } = await uploadFileRobust(
          'customer-documents',
          rPath,
          depositReceipt,
          toast
        );
        if (upErr) throw upErr;
        receiptUrl = rPath;
      }

      // Create booking
      const { data: booking, error } = await supabase
        .from('bubatrent_booking_bookings')
        .insert({
          car_id: selectedCar.id,
          user_id: selectedCust.id,
          pickup_date: pickupDate,
          return_date: returnDate,
          total_price: totalPrice,
          deposit_amount: depositAmount,
          status: initialStatus,
          fleet_group_id: activeFleetId,
          customer_name: selectedCust.display_name || '',
          customer_email: selectedCust.username || '',
          customer_phone: selectedCust.phone || '',
          deposit_receipt_path: receiptUrl,
          deposit_status: receiptUrl ? 'uploaded' : 'pending',
        })
        .select()
        .single();
      if (error) throw error;

      // If receipt uploaded and status = DEPOSIT_PAID or CONFIRMED, create payment record
      if (receiptUrl && (initialStatus === 'DEPOSIT_PAID' || initialStatus === 'CONFIRMED')) {
        await supabase.from('bubatrent_booking_payments').insert({
          booking_id: booking.id,
          amount: depositAmount,
          payment_method: 'bank_transfer',
          status: 'completed',
          reference_number: `ADMIN-${Date.now()}`,
          fleet_group_id: activeFleetId,
        });
      }

      // Audit log
      await supabase.from('bubatrent_booking_audit_logs').insert({
        admin_id: user.id,
        action: 'ADMIN_CREATE_BOOKING',
        resource_type: 'booking',
        resource_id: booking.id,
        details: {
          customer_id: selectedCust.id,
          car_id: selectedCar.id,
          dates: `${pickupDate} → ${returnDate}`,
          status: initialStatus,
          total: totalPrice,
          deposit: depositAmount,
        },
      });

      toast.success('Booking created successfully');
      navigate(`/admin/bookings/${booking.id}`);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setCreating(false);
    }
  }

  return (
    <AdminLayout title="Book for Customer">
      <button
        onClick={() => navigate('/admin/bookings')}
        className="flex items-center gap-1.5 text-sm text-slate-500 hover:text-white mb-4 transition-colors"
      >
        <ArrowLeft className="w-4 h-4" /> Back to Bookings
      </button>

      {/* Step indicators */}
      <div className="flex gap-2 mb-6">
        {['Customer', 'Car', 'Dates & Deposit', 'Confirm'].map((s, i) => (
          <div
            key={s}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium ${
              step === i + 1
                ? 'bg-violet-500/20 text-violet-300 border border-violet-500/30'
                : step > i + 1
                  ? 'bg-green-500/10 text-green-400'
                  : 'bg-white/5 text-slate-500'
            }`}
          >
            {step > i + 1 ? (
              <Check className="w-3 h-3" />
            ) : (
              <span className="w-3 text-center">{i + 1}</span>
            )}
            {s}
          </div>
        ))}
      </div>

      {/* Step 1: Select Customer */}
      {step === 1 && (
        <div className="glass-card max-w-2xl">
          <h3 className="text-sm font-semibold text-white mb-3">Select Customer</h3>
          <div className="relative mb-3">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
            <input
              value={custSearch}
              onChange={(e) => handleCustSearch(e.target.value)}
              className="input-field !pl-10"
              placeholder="Search by name, phone, IC, or email..."
              autoFocus
            />
            {searching && (
              <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 animate-spin" />
            )}
          </div>
          {selectedCust ? (
            <div className="bg-violet-500/5 border border-violet-500/20 rounded-xl p-3 mb-3 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <User className="w-4 h-4 text-violet-400" />
                <div>
                  <p className="text-sm text-white font-medium">
                    {selectedCust.display_name || selectedCust.ic_number}
                  </p>
                  <p className="text-[10px] text-slate-500">
                    {selectedCust.phone} {selectedCust.username ? `• ${selectedCust.username}` : ''}
                  </p>
                </div>
              </div>
              <button
                onClick={() => setSelectedCust(null)}
                className="text-slate-500 text-xs hover:text-white"
              >
                Change
              </button>
            </div>
          ) : (
            custResults.length > 0 && (
              <div className="space-y-1 max-h-48 overflow-y-auto">
                {custResults.map((c) => (
                  <button
                    key={c.id}
                    onClick={() => {
                      setSelectedCust(c);
                      setCustResults([]);
                    }}
                    className="w-full flex items-center gap-3 p-2.5 rounded-xl hover:bg-white/5 text-left transition-all"
                  >
                    <User className="w-4 h-4 text-slate-400" />
                    <div>
                      <p className="text-sm text-white">
                        {c.display_name || c.ic_number || 'Unknown'}
                      </p>
                      <p className="text-[10px] text-slate-500">
                        {c.phone} {c.username ? `• ${c.username}` : ''}{' '}
                        {c.is_verified ? '✓ Verified' : ''}
                      </p>
                    </div>
                  </button>
                ))}
              </div>
            )
          )}
          <button
            onClick={() => step === 1 && selectedCust && setStep(2)}
            disabled={!selectedCust}
            className="btn-primary w-full mt-4 disabled:opacity-30"
          >
            Next → Select Car
          </button>
        </div>
      )}

      {/* Step 2: Select Car */}
      {step === 2 && (
        <div className="glass-card max-w-2xl">
          <h3 className="text-sm font-semibold text-white mb-3">
            Select Car — {activeFleet?.name}
          </h3>
          {carsLoading ? (
            <LoadingSpinner />
          ) : (
            <div className="space-y-2 max-h-64 overflow-y-auto">
              {cars.map((c) => (
                <button
                  key={c.id}
                  onClick={() => setSelectedCar(c)}
                  className={`w-full flex items-center gap-3 p-3 rounded-xl text-left transition-all border ${
                    selectedCar?.id === c.id
                      ? 'bg-violet-500/10 border-violet-500/30'
                      : 'bg-white/5 border-transparent hover:bg-white/10'
                  }`}
                >
                  {c.image_url && (
                    <img src={c.image_url} className="w-14 h-10 rounded-lg object-cover" alt="" />
                  )}
                  <div>
                    <p className="text-sm text-white font-medium">
                      {c.name || `${c.brand} ${c.model}`}
                    </p>
                    <p className="text-[10px] text-slate-500">
                      RM{c.price_per_day}/day • {c.plate_number}
                    </p>
                  </div>
                </button>
              ))}
            </div>
          )}
          <div className="flex gap-2 mt-4">
            <button onClick={() => setStep(1)} className="btn-secondary flex-1">
              Back
            </button>
            <button
              onClick={() => selectedCar && setStep(3)}
              disabled={!selectedCar}
              className="btn-primary flex-1 disabled:opacity-30"
            >
              Next → Dates
            </button>
          </div>
        </div>
      )}

      {/* Step 3: Dates & Deposit */}
      {step === 3 && (
        <div className="glass-card max-w-2xl">
          <h3 className="text-sm font-semibold text-white mb-3">Dates & Deposit</h3>

          {/* Existing bookings for this car */}
          {existingBookings.length > 0 && (
            <div className="mb-4 rounded-xl border border-white/10 overflow-hidden">
              <div className="px-3 py-2 bg-white/5 text-[10px] font-semibold text-slate-400 uppercase tracking-wider">
                Existing bookings for {selectedCar?.name}
              </div>
              <div className="divide-y divide-white/5 max-h-36 overflow-y-auto">
                {existingBookings.map((b) => (
                  <div
                    key={b.id}
                    className={`px-3 py-2 flex items-center justify-between text-xs ${
                      BLOCKING_STATUSES.includes(b.status) ? 'bg-red-500/5' : 'bg-yellow-500/5'
                    }`}
                  >
                    <div className="flex items-center gap-2">
                      <span
                        className={`w-1.5 h-1.5 rounded-full ${
                          BLOCKING_STATUSES.includes(b.status) ? 'bg-red-400' : 'bg-yellow-400'
                        }`}
                      />
                      <span className="text-slate-300">
                        {b.pickup_date} → {b.return_date}
                      </span>
                      {b.customer_name && (
                        <span className="text-slate-500">({b.customer_name})</span>
                      )}
                    </div>
                    <span
                      className={`text-[10px] font-bold uppercase px-1.5 py-0.5 rounded ${
                        BLOCKING_STATUSES.includes(b.status)
                          ? 'bg-red-500/20 text-red-300'
                          : 'bg-yellow-500/20 text-yellow-300'
                      }`}
                    >
                      {b.status}
                      {b.status === 'HOLD' ? ' (available)' : ''}
                    </span>
                  </div>
                ))}
              </div>
              <div className="px-3 py-1.5 bg-white/[0.02] text-[10px] text-slate-500 flex items-center gap-3">
                <span className="flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-red-400" /> Blocks dates
                </span>
                <span className="flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-yellow-400" /> HOLD (still available)
                </span>
              </div>
            </div>
          )}

          <div className="grid grid-cols-2 gap-3 mb-3">
            <div>
              <label className="input-label">Pickup Date *</label>
              <input
                type="date"
                value={pickupDate}
                onChange={(e) => setPickupDate(e.target.value)}
                min={new Date().toISOString().split('T')[0]}
                className="input-field"
              />
            </div>
            <div>
              <label className="input-label">Return Date *</label>
              <input
                type="date"
                value={returnDate}
                onChange={(e) => setReturnDate(e.target.value)}
                min={pickupDate || new Date().toISOString().split('T')[0]}
                className="input-field"
              />
            </div>
          </div>
          {dateError && (
            <p className="text-xs text-red-400 mb-2 flex items-center gap-1">
              <AlertTriangle className="w-3 h-3" /> {dateError}
            </p>
          )}
          {/* Real-time overlap warning */}
          {pickupDate && returnDate && getOverlap() && !dateError && (
            <div className="flex items-center gap-2 text-xs text-red-400 bg-red-500/10 border border-red-500/20 rounded-xl px-3 py-2 mb-3">
              <AlertTriangle className="w-3.5 h-3.5 shrink-0" />
              <span>
                These dates overlap with a <strong>{getOverlap().status}</strong> booking (
                {getOverlap().pickup_date} → {getOverlap().return_date}). You won't be able to
                proceed.
              </span>
            </div>
          )}
          {pickupDate && returnDate && selectedCar && !getOverlap() && (
            <div className="bg-white/5 rounded-xl p-3 mb-3">
              <p className="text-sm text-white">
                Total: <strong>RM {calcTotal().toFixed(2)}</strong> (
                {Math.ceil((new Date(returnDate) - new Date(pickupDate)) / 86400000)} days × RM
                {selectedCar.price_per_day})
              </p>
            </div>
          )}
          <div className="grid grid-cols-2 gap-3 mb-3">
            <div>
              <label className="input-label">Deposit (min RM100) *</label>
              <input
                type="number"
                value={depositAmount}
                onChange={(e) => setDepositAmount(Number(e.target.value))}
                min={100}
                className="input-field"
              />
            </div>
            <div>
              <label className="input-label">Initial Status</label>
              <select
                value={initialStatus}
                onChange={(e) => setInitialStatus(e.target.value)}
                className="input-field"
              >
                <option value="DEPOSIT_PAID">Deposit Paid</option>
                <option value="CONFIRMED">Confirmed</option>
              </select>
            </div>
          </div>
          <div className="mb-3">
            <label className="input-label">Deposit Receipt (optional)</label>
            <label
              className={`flex items-center gap-2 px-3 py-2.5 rounded-xl text-xs cursor-pointer border ${depositReceipt ? 'bg-green-500/5 border-green-500/20 text-green-300' : 'bg-white/5 border-white/10 text-slate-300 hover:bg-white/10'}`}
            >
              <FileImage className="w-4 h-4" />
              <span className="truncate">
                {depositReceipt?.name || 'Upload deposit receipt...'}
              </span>
              <input
                type="file"
                accept="image/*,.pdf"
                className="hidden"
                onChange={(e) => setDepositReceipt(e.target.files[0])}
              />
            </label>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setStep(2)} className="btn-secondary flex-1">
              Back
            </button>
            <button
              onClick={() => {
                if (validateDates()) setStep(4);
              }}
              disabled={!!getOverlap()}
              className="btn-primary flex-1 disabled:opacity-30"
            >
              Review & Confirm
            </button>
          </div>
        </div>
      )}

      {/* Step 4: Confirm */}
      {step === 4 && (
        <div className="glass-card max-w-2xl">
          <h3 className="text-sm font-semibold text-white mb-4">Review Booking</h3>
          <div className="space-y-2 mb-4">
            <div className="flex justify-between text-sm">
              <span className="text-slate-400">Customer:</span>
              <span className="text-white">
                {selectedCust?.display_name || selectedCust?.ic_number}
              </span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-slate-400">Car:</span>
              <span className="text-white">
                {selectedCar?.name || `${selectedCar?.brand} ${selectedCar?.model}`}
              </span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-slate-400">Dates:</span>
              <span className="text-white">
                {pickupDate} → {returnDate}
              </span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-slate-400">Total:</span>
              <span className="text-white font-semibold">RM {calcTotal().toFixed(2)}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-slate-400">Deposit:</span>
              <span className="text-white">RM {depositAmount}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-slate-400">Status:</span>
              <span className="text-green-400">{initialStatus}</span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-slate-400">Fleet:</span>
              <span className="text-white">{activeFleet?.name}</span>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setStep(3)} className="btn-secondary flex-1">
              Back
            </button>
            <button
              onClick={handleCreate}
              disabled={creating}
              className="btn-primary flex-1 flex items-center justify-center gap-2"
            >
              {creating ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Shield className="w-4 h-4" />
              )}
              {creating ? 'Creating...' : 'Create Booking'}
            </button>
          </div>
        </div>
      )}
    </AdminLayout>
  );
}

