// Status flow definition
const STATUS_FLOW = {
  HOLD: ['DEPOSIT_PAID', 'CANCELLED'],
  DEPOSIT_PAID: ['CONFIRMED', 'CANCELLED'],
  CONFIRMED: ['PICKUP', 'CANCELLED'],
  PICKUP: ['RETURNED'],
  RETURNED: [],
  CANCELLED: [],
  EXPIRED: ['DEPOSIT_PAID'],
};

export default function AdminBookingDetail() {
  const { id } = useParams();
  const { user } = useAuth();
  const { activeFleetId } = useFleet();
  const toast = useToast();
  const navigate = useNavigate();
  const [booking, setBooking] = useState(null);
  const [documents, setDocuments] = useState([]);
  const [auditLogs, setAuditLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [notFound, setNotFound] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [agreement, setAgreement] = useState(null);

  // Date editing
  const [editingDates, setEditingDates] = useState(false);
  const [editPickup, setEditPickup] = useState('');
  const [editReturn, setEditReturn] = useState('');
  const [reactivateReason, setReactivateReason] = useState('');
  const [showReactivate, setShowReactivate] = useState(false);
  const [reactivating, setReactivating] = useState(false);
  const [savingDates, setSavingDates] = useState(false);

  // Full payment receipt upload
  const [fullPaymentFile, setFullPaymentFile] = useState(null);
  const [uploadingReceipt, setUploadingReceipt] = useState(false);

  useEffect(() => {
    async function fetchAll() {
      try {
        console.log('[BookingDetail] Fetching booking:', id, 'activeFleetId:', activeFleetId);

        // Admin-direct query: fetch by ID without user_id filter
        const { data: bookingData, error: bookingErr } = await supabase
          .from('bubatrent_booking_bookings')
          .select('*, bubatrent_booking_cars(*), bubatrent_booking_payments(*)')
          .eq('id', id)
          .maybeSingle();

        if (bookingErr) {
          console.error('[BookingDetail] Query error:', bookingErr);
          throw bookingErr;
        }
        if (!bookingData) {
          console.warn('[BookingDetail] No booking found for id:', id);
          setNotFound(true);
          return;
        }

        console.log(
          '[BookingDetail] Booking loaded:',
          bookingData.id,
          'status:',
          bookingData.status
        );
        setBooking(bookingData);
        setEditPickup(bookingData.pickup_date);
        setEditReturn(bookingData.return_date);

        // Fetch docs, logs, and agreement in parallel
        try {
          const [docsData, logsData, agreementData] = await Promise.all([
            getBookingDocuments(id, user.id).catch((err) => {
              console.warn('[BookingDetail] Docs error:', err);
              return [];
            }),
            getAuditLogs(id).catch((err) => {
              console.warn('[BookingDetail] Logs error:', err);
              return [];
            }),
            supabase
              .from('bubatrent_booking_rental_agreements')
              .select('id, agreed_at, customer_name, signature_data')
              .eq('booking_id', id)
              .maybeSingle()
              .then((r) => r.data)
              .catch(() => null),
          ]);
          setDocuments(docsData);
          setAuditLogs(logsData);
          setAgreement(agreementData);
        } catch (subErr) {
          console.warn('[BookingDetail] Error fetching docs/logs:', subErr);
        }
      } catch (err) {
        console.error('[BookingDetail] Error fetching booking:', err);
        setNotFound(true);
      } finally {
        setLoading(false);
      }
    }
    fetchAll();
  }, [id, user.id, activeFleetId]);

  function copyAgreementLink() {
    const url = `${window.location.origin}/booking/${id}/agreement`;
    navigator.clipboard.writeText(url);
    toast.success('Agreement link copied! Share with the customer via WhatsApp.');
  }

  async function handleStatusChange(newStatus) {
    try {
      // Block PICKUP unless agreement is signed
      if (newStatus === 'PICKUP' && !agreement) {
        toast.error(
          'Cannot mark as Picked Up — rental agreement has not been signed yet. Send the agreement link to the customer first.'
        );
        return;
      }

      // Block PICKUP unless full payment is received
      if (newStatus === 'PICKUP') {
        const payments = booking.bubatrent_booking_payments || [];
        const totalPaid = payments
          .filter((p) => p.status === 'completed')
          .reduce((sum, p) => sum + Number(p.amount || 0), 0);
        const totalPrice = Number(booking.total_price || 0);
        // Also accept if both receipts are verified (handles legacy data before payment record fix)
        const receiptsVerified =
          booking.deposit_status === 'verified' && booking.full_payment_status === 'verified';
        if (totalPaid < totalPrice && !receiptsVerified) {
          const outstanding = totalPrice - totalPaid;
          toast.error(
            `Cannot mark as Picked Up — full payment required. Outstanding: RM ${outstanding.toFixed(2)} (Paid: RM ${totalPaid.toFixed(2)} / Total: RM ${totalPrice.toFixed(2)})`
          );
          return;
        }
      }

      const updates = { status: newStatus };
      // When marking as RETURNED, set actual_return_date
      if (newStatus === 'RETURNED') {
        updates.actual_return_date = new Date().toISOString().split('T')[0];
      }
      const { error } = await supabase
        .from('bubatrent_booking_bookings')
        .update(updates)
        .eq('id', id);
      if (error) throw error;
      setBooking((prev) => ({ ...prev, ...updates }));
      toast.success(`Status updated to ${newStatus}`);
    } catch (err) {
      toast.error(err.message);
    }
  }

  async function handleVerify(docId) {
    try {
      await verifyDocument(docId, user.id);
      const docsData = await getBookingDocuments(id, user.id);
      setDocuments(docsData);
      const logsData = await getAuditLogs(id);
      setAuditLogs(logsData);
    } catch (err) {
      toast.error(err.message);
    }
  }

  async function handleSaveDates() {
    setSavingDates(true);
    try {
      const { error } = await supabase
        .from('bubatrent_booking_bookings')
        .update({ pickup_date: editPickup, return_date: editReturn })
        .eq('id', id);
      if (error) throw error;
      setBooking((prev) => ({ ...prev, pickup_date: editPickup, return_date: editReturn }));
      setEditingDates(false);
      toast.success('Dates updated!');
    } catch (err) {
      toast.error(err.message);
    } finally {
      setSavingDates(false);
    }
  }

  async function handleVerifyDeposit() {
    try {
      const { error } = await supabase
        .from('bubatrent_booking_bookings')
        .update({ deposit_status: 'verified' })
        .eq('id', id);
      if (error) throw error;

      // Also mark the deposit payment record as completed
      await supabase
        .from('bubatrent_booking_payments')
        .update({ status: 'completed' })
        .eq('booking_id', id)
        .eq('payment_type', 'deposit');

      // Increase customer deposit credit by the deposit amount
      if (booking.deposit_amount > 0) {
        const profileData = await supabase
          .from('bubatrent_booking_profiles')
          .select('deposit_credit')
          .eq('id', booking.user_id)
          .single();
        const currentCredit = Number(profileData.data?.deposit_credit || 0);
        await supabase
          .from('bubatrent_booking_profiles')
          .update({ deposit_credit: currentCredit + Number(booking.deposit_amount) })
          .eq('id', booking.user_id);
        await supabase.from('bubatrent_booking_credit_transactions').insert({
          user_id: booking.user_id,
          booking_id: id,
          amount: Number(booking.deposit_amount),
          type: 'deposit_paid',
          description: `Deposit verified — credit added`,
          admin_id: user.id,
        });
      }

      // Refresh booking with updated payment data
      const { data: refreshed } = await supabase
        .from('bubatrent_booking_bookings')
        .select('*, bubatrent_booking_cars(*), bubatrent_booking_payments(*)')
        .eq('id', id)
        .maybeSingle();
      if (refreshed) setBooking(refreshed);

      toast.success('Deposit receipt verified! Customer credit updated.');
    } catch (err) {
      toast.error(err.message);
    }
  }

  async function handleRejectDeposit() {
    try {
      const { error } = await supabase
        .from('bubatrent_booking_bookings')
        .update({ deposit_status: 'rejected' })
        .eq('id', id);
      if (error) throw error;
      setBooking((prev) => ({ ...prev, deposit_status: 'rejected' }));
      toast.success('Deposit receipt rejected.');
    } catch (err) {
      toast.error(err.message);
    }
  }

  async function handleVerifyFullPayment() {
    try {
      const { error } = await supabase
        .from('bubatrent_booking_bookings')
        .update({ full_payment_status: 'verified' })
        .eq('id', id);
      if (error) throw error;

      // Update or create the full payment record as completed
      const { data: existing } = await supabase
        .from('bubatrent_booking_payments')
        .select('id')
        .eq('booking_id', id)
        .eq('payment_type', 'full_payment')
        .maybeSingle();

      if (existing) {
        await supabase
          .from('bubatrent_booking_payments')
          .update({ status: 'completed' })
          .eq('id', existing.id);
      } else {
        await supabase.from('bubatrent_booking_payments').insert({
          booking_id: id,
          amount: booking.full_payment_amount || booking.total_price,
          payment_method: 'bank_transfer',
          status: 'completed',
          payment_type: 'full_payment',
          reference_number: `FP-${Date.now().toString(36).toUpperCase()}`,
        });
      }

      // Refresh booking with updated payment data
      const { data: refreshed } = await supabase
        .from('bubatrent_booking_bookings')
        .select('*, bubatrent_booking_cars(*), bubatrent_booking_payments(*)')
        .eq('id', id)
        .maybeSingle();
      if (refreshed) setBooking(refreshed);

      toast.success('Full payment verified!');
    } catch (err) {
      toast.error(err.message);
    }
  }

  async function handleUploadFullPayment() {
    if (!fullPaymentFile) {
      toast.error('Select a receipt file first.');
      return;
    }
    setUploadingReceipt(true);
    try {
      const ext = fullPaymentFile.name.split('.').pop();
      const path = `receipts/${id}/full_payment_${Date.now()}.${ext}`;
      const { error: upErr } = await uploadFileRobust(
        'customer-documents',
        path,
        fullPaymentFile,
        toast
      );
      if (upErr) throw upErr;
      const { error } = await supabase
        .from('bubatrent_booking_bookings')
        .update({ full_payment_receipt_path: path, full_payment_status: 'uploaded' })
        .eq('id', id);
      if (error) throw error;
      setBooking((prev) => ({
        ...prev,
        full_payment_receipt_path: path,
        full_payment_status: 'uploaded',
      }));
      setFullPaymentFile(null);
      toast.success('Full payment receipt uploaded!');
    } catch (err) {
      toast.error(err.message);
    } finally {
      setUploadingReceipt(false);
    }
  }

  // Delete booking and all related records
  async function handleDeleteBooking() {
    const confirmMsg = `Are you sure you want to DELETE this booking?\n\nCar: ${booking.bubatrent_booking_cars?.name || 'Unknown'}\nDates: ${booking.pickup_date} → ${booking.return_date}\nStatus: ${booking.status}\n\nThis will permanently delete:\n• The booking record\n• Associated payments\n• Audit logs\n\nThis action CANNOT be undone.`;
    if (!window.confirm(confirmMsg)) return;

    setDeleting(true);
    try {
      // Delete related records in dependency order
      await supabase.from('bubatrent_booking_credit_transactions').delete().eq('booking_id', id);
      await supabase.from('bubatrent_booking_payments').delete().eq('booking_id', id);
      await supabase.from('bubatrent_booking_audit_logs').delete().eq('resource_id', id);
      // Delete the booking itself
      const { error } = await supabase.from('bubatrent_booking_bookings').delete().eq('id', id);
      if (error) throw error;

      toast.success('Booking deleted successfully');
      navigate('/admin/bookings');
    } catch (err) {
      toast.error('Failed to delete: ' + err.message);
      setDeleting(false);
    }
  }

  if (loading)
    return (
      <AdminLayout>
        <LoadingSpinner fullScreen />
      </AdminLayout>
    );
  if (notFound || !booking)
    return (
      <AdminLayout>
        <p className="text-red-400">Booking not found or you don't have access.</p>
        <p className="text-xs text-slate-500 mt-1">ID: {id}</p>
        <Link
          to="/admin/bookings"
          className="text-violet-400 text-sm mt-3 inline-block hover:underline"
        >
          ← Back to Bookings
        </Link>
      </AdminLayout>
    );

  const car = booking.bubatrent_booking_cars;
  const payment = booking.bubatrent_booking_payments?.[0];
  const nextStatuses = STATUS_FLOW[booking.status] || [];

  return (
    <AdminLayout>
      <Link
        to="/admin/bookings"
        className="inline-flex items-center gap-1.5 text-sm text-slate-500 hover:text-white transition-colors mb-6"
      >
        <ArrowLeft className="w-4 h-4" /> All Bookings
      </Link>

      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 mb-6">
        <div>
          <h1 className="text-xl font-bold text-white flex items-center gap-3">
            Booking Detail <BookingStatusBadge status={booking.status} />
          </h1>
          <p className="text-xs text-slate-500 mt-1 font-mono">{booking.id}</p>
        </div>
        <div className="flex flex-wrap gap-2">
          {nextStatuses.map((ns) => (
            <button
              key={ns}
              onClick={() => {
                if (booking.status === 'EXPIRED') {
                  setShowReactivate(true);
                  return;
                }
                handleStatusChange(ns);
              }}
              className={`px-3 py-1.5 rounded-lg text-xs sm:text-sm font-medium transition-colors ${
                ns === 'CANCELLED'
                  ? 'bg-red-500/10 text-red-400 hover:bg-red-500/20'
                  : ns === 'RETURNED'
                    ? 'bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20'
                    : 'bg-green-500/10 text-green-400 hover:bg-green-500/20'
              }`}
            >
              {ns === 'DEPOSIT_PAID'
                ? booking.status === 'EXPIRED'
                  ? 'Reactivate → Deposit Paid'
                  : 'Mark Deposit Paid'
                : ns === 'CONFIRMED'
                  ? booking.status === 'EXPIRED'
                    ? 'Reactivate → Confirmed'
                    : 'Confirm'
                  : ns === 'PICKUP'
                    ? 'Mark Picked Up'
                    : ns === 'RETURNED'
                      ? 'Mark Returned'
                      : ns === 'CANCELLED'
                        ? 'Cancel'
                        : ns}
            </button>
          ))}
          <button
            onClick={handleDeleteBooking}
            disabled={deleting}
            className="px-3 py-1.5 rounded-lg text-xs sm:text-sm font-medium bg-red-500/10 text-red-400 hover:bg-red-500/20 transition-colors flex items-center gap-1.5"
          >
            <Trash2 className="w-3.5 h-3.5" />
            {deleting ? 'Deleting...' : 'Delete'}
          </button>
        </div>
      </div>

      {/* Rental Agreement Status Card */}
      {['CONFIRMED', 'PICKUP', 'RETURNED'].includes(booking.status) && (
        <div
          className={`glass-card mb-6 flex flex-col sm:flex-row items-start sm:items-center gap-4 ${agreement ? 'border-green-500/20 bg-green-500/5' : 'border-amber-500/20 bg-amber-500/5'}`}
        >
          <div className="flex items-center gap-3 flex-1">
            <FileSignature
              className={`w-6 h-6 shrink-0 ${agreement ? 'text-green-400' : 'text-amber-400'}`}
            />
            <div>
              <p
                className={`text-sm font-medium ${agreement ? 'text-green-300' : 'text-amber-300'}`}
              >
                {agreement ? 'Rental Agreement Signed' : 'Rental Agreement Not Signed'}
              </p>
              <p className="text-xs text-slate-500">
                {agreement
                  ? `Signed by ${agreement.customer_name} on ${new Date(agreement.agreed_at).toLocaleString()}`
                  : 'Customer must sign the agreement before vehicle pickup.'}
              </p>
            </div>
          </div>
          {!agreement && (
            <button
              onClick={copyAgreementLink}
              className="flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-medium bg-violet-500/10 text-violet-400 hover:bg-violet-500/20 transition-colors whitespace-nowrap"
            >
              <ClipboardCopy className="w-4 h-4" />
              Copy Agreement Link
            </button>
          )}
          {agreement && (
            <div className="flex items-center gap-3">
              {agreement.signature_data && (
                <div className="bg-white rounded-lg p-2 w-32 h-16">
                  <img
                    src={agreement.signature_data}
                    alt="Signature"
                    className="w-full h-full object-contain"
                  />
                </div>
              )}
              <a
                href={`/booking/${id}/agreement`}
                target="_blank"
                rel="noreferrer"
                className="flex items-center gap-1.5 px-3 py-2 rounded-lg text-xs font-medium bg-green-500/10 text-green-400 hover:bg-green-500/20 transition-colors whitespace-nowrap"
              >
                <Eye className="w-3.5 h-3.5" /> View Full Agreement
              </a>
            </div>
          )}
        </div>
      )}

      {/* Reactivation Modal */}
      {showReactivate && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm"
          onClick={() => setShowReactivate(false)}
        >
          <div
            className="glass-card w-full max-w-md animate-fade-in"
            onClick={(e) => e.stopPropagation()}
          >
            <h3 className="text-lg font-semibold text-white mb-2">Reactivate Expired Booking</h3>
            <p className="text-sm text-slate-400 mb-4">
              This booking expired. Provide a reason for reactivation:
            </p>
            <textarea
              value={reactivateReason}
              onChange={(e) => setReactivateReason(e.target.value)}
              className="input-field mb-4"
              rows={3}
              placeholder="Reason for reactivation (required)..."
            />
            <div className="flex flex-col sm:flex-row gap-2">
              <button onClick={() => setShowReactivate(false)} className="btn-secondary flex-1">
                Cancel
              </button>
              {nextStatuses
                .filter((s) => s !== 'CANCELLED')
                .map((ns) => (
                  <button
                    key={ns}
                    disabled={!reactivateReason.trim() || reactivating}
                    onClick={async () => {
                      setReactivating(true);
                      try {
                        // Check date overlap
                        const { data: overlapping } = await supabase
                          .from('bubatrent_booking_bookings')
                          .select('id')
                          .eq('car_id', booking.car_id)
                          .in('status', ['HOLD', 'DEPOSIT_PAID', 'CONFIRMED', 'PICKUP'])
                          .lte('pickup_date', booking.return_date)
                          .gte('return_date', booking.pickup_date)
                          .neq('id', booking.id)
                          .limit(1);
                        if (overlapping?.length > 0) {
                          toast.error(
                            'Cannot reactivate: date overlap with another booking. Edit dates first.'
                          );
                          setReactivating(false);
                          return;
                        }
                        await supabase
                          .from('bubatrent_booking_bookings')
                          .update({
                            status: ns,
                            reactivated_by: user.id,
                            reactivated_at: new Date().toISOString(),
                            reactivation_reason: reactivateReason,
                          })
                          .eq('id', booking.id);
                        await supabase.from('bubatrent_booking_audit_logs').insert({
                          admin_id: user.id,
                          action: 'REACTIVATE_EXPIRED',
                          resource_type: 'booking',
                          resource_id: booking.id,
                          details: { new_status: ns, reason: reactivateReason },
                        });
                        setBooking((prev) => ({ ...prev, status: ns }));
                        toast.success(`Booking reactivated → ${ns}`);
                        setShowReactivate(false);
                        setReactivateReason('');
                      } catch (err) {
                        toast.error(err.message);
                      } finally {
                        setReactivating(false);
                      }
                    }}
                    className="flex-1 px-4 py-2.5 rounded-xl text-sm font-medium bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/20 transition-all disabled:opacity-30"
                  >
                    {reactivating
                      ? 'Activating...'
                      : `→ ${ns === 'DEPOSIT_PAID' ? 'Deposit Paid' : 'Confirmed'}`}
                  </button>
                ))}
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Main info */}
        <div className="lg:col-span-2 space-y-6">
          {/* Car & Dates */}
          <div className="glass-card">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
                Rental Details
              </h3>
              {!editingDates && ['HOLD', 'DEPOSIT_PAID', 'CONFIRMED'].includes(booking.status) && (
                <button
                  onClick={() => setEditingDates(true)}
                  className="flex items-center gap-1 text-xs text-violet-400 hover:text-violet-300"
                >
                  <Edit3 className="w-3.5 h-3.5" /> Edit Dates
                </button>
              )}
            </div>
            <div className="flex items-center gap-4 mb-4">
              {car?.image_url && (
                <img
                  src={car.image_url}
                  alt={car?.name}
                  className="w-24 h-16 rounded-xl object-cover"
                />
              )}
              <div>
                <div className="flex items-center gap-2">
                  <p className="text-white font-semibold">{car?.name}</p>
                  {car?.plate_number && (
                    <span className="text-[10px] font-mono px-1.5 py-0.5 rounded bg-violet-500/10 text-violet-300 border border-violet-500/20">
                      {car.plate_number}
                    </span>
                  )}
                </div>
                <p className="text-xs text-slate-500">
                  {car?.brand} {car?.model} · {car?.year}
                </p>
              </div>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 text-sm">
              <div>
                <p className="text-xs text-slate-500 mb-1">Pick-up</p>
                {editingDates ? (
                  <input
                    type="date"
                    value={editPickup}
                    onChange={(e) => setEditPickup(e.target.value)}
                    className="input-field !py-1.5 text-sm"
                  />
                ) : (
                  <p className="text-white">{formatDate(booking.pickup_date)}</p>
                )}
              </div>
              <div>
                <p className="text-xs text-slate-500 mb-1">Return</p>
                {editingDates ? (
                  <input
                    type="date"
                    value={editReturn}
                    onChange={(e) => setEditReturn(e.target.value)}
                    className="input-field !py-1.5 text-sm"
                  />
                ) : (
                  <p className="text-white">{formatDate(booking.return_date)}</p>
                )}
              </div>
              <div>
                <p className="text-xs text-slate-500 mb-1">Total</p>
                <p className="text-white font-semibold">{formatMYR(booking.total_price)}</p>
              </div>
              <div>
                <p className="text-xs text-slate-500 mb-1">Deposit</p>
                <p className="text-green-400 font-semibold">{formatMYR(booking.deposit_amount)}</p>
              </div>
            </div>
            {editingDates && (
              <div className="flex gap-2 mt-4">
                <button
                  onClick={handleSaveDates}
                  disabled={savingDates}
                  className="btn-primary !px-4 !py-2 text-sm flex items-center gap-1"
                >
                  <Save className="w-3.5 h-3.5" /> {savingDates ? 'Saving...' : 'Save'}
                </button>
                <button
                  onClick={() => {
                    setEditingDates(false);
                    setEditPickup(booking.pickup_date);
                    setEditReturn(booking.return_date);
                  }}
                  className="btn-secondary !px-4 !py-2 text-sm flex items-center gap-1"
                >
                  <X className="w-3.5 h-3.5" /> Cancel
                </button>
              </div>
            )}
            {booking.actual_return_date && (
              <p className="text-xs text-emerald-400 mt-3">
                Actual return: {formatDate(booking.actual_return_date)}
              </p>
            )}
            {Number(booking.credit_applied || 0) > 0 && (
              <p className="text-xs text-green-400 mt-2 flex items-center gap-1">
                <Wallet className="w-3 h-3" /> Credit applied: {formatMYR(booking.credit_applied)}
              </p>
            )}
          </div>

          {/* Customer Info */}
          <div className="glass-card">
            <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4">
              Customer
            </h3>
            <div className="space-y-3 text-sm">
              <div className="flex items-center gap-2">
                <User className="w-4 h-4 text-violet-400" />
                <span className="text-white">{booking.customer_name}</span>
              </div>
              <div className="flex items-center gap-2">
                <Mail className="w-4 h-4 text-violet-400" />
                <span className="text-slate-300">{booking.customer_email}</span>
              </div>
              <div className="flex items-center gap-2">
                <Phone className="w-4 h-4 text-violet-400" />
                <span className="text-slate-300">{booking.customer_phone}</span>
              </div>
              {booking.notes && (
                <div className="flex items-start gap-2">
                  <FileText className="w-4 h-4 text-violet-400 mt-0.5" />
                  <span className="text-slate-300">{booking.notes}</span>
                </div>
              )}
            </div>
          </div>

          {/* Receipt Verification */}
          <div className="glass-card">
            <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
              <FileCheck className="w-4 h-4" /> Payment Receipts
            </h3>
            <div className="space-y-4">
              {/* Deposit Receipt */}
              <div className="bg-white/[0.02] rounded-xl p-4">
                <div className="flex items-center justify-between mb-2">
                  <p className="text-sm text-white font-medium">Deposit Receipt</p>
                  <span
                    className={`text-xs px-2 py-0.5 rounded-full ${
                      booking.deposit_status === 'verified'
                        ? 'bg-green-500/10 text-green-400'
                        : booking.deposit_status === 'uploaded'
                          ? 'bg-yellow-500/10 text-yellow-400'
                          : booking.deposit_status === 'rejected'
                            ? 'bg-red-500/10 text-red-400'
                            : 'bg-slate-500/10 text-slate-400'
                    }`}
                  >
                    {booking.deposit_status || 'pending'}
                  </span>
                </div>
                {booking.deposit_receipt_path && (
                  <a
                    href={
                      supabase.storage
                        .from('customer-documents')
                        .getPublicUrl(booking.deposit_receipt_path).data.publicUrl
                    }
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-xs text-violet-400 hover:text-violet-300 flex items-center gap-1 mb-2"
                  >
                    <Eye className="w-3 h-3" /> View Receipt
                  </a>
                )}
                {booking.deposit_status === 'uploaded' && (
                  <div className="flex gap-2 mt-2">
                    <button
                      onClick={handleVerifyDeposit}
                      className="px-3 py-1.5 rounded-lg text-xs bg-green-500/10 text-green-400 hover:bg-green-500/20 transition-colors"
                    >
                      ✓ Verify
                    </button>
                    <button
                      onClick={handleRejectDeposit}
                      className="px-3 py-1.5 rounded-lg text-xs bg-red-500/10 text-red-400 hover:bg-red-500/20 transition-colors"
                    >
                      ✗ Reject
                    </button>
                  </div>
                )}
              </div>

              {/* Full Payment */}
              <div className="bg-white/[0.02] rounded-xl p-4">
                <div className="flex items-center justify-between mb-2">
                  <p className="text-sm text-white font-medium">
                    Full Payment ({formatMYR(booking.full_payment_amount || booking.total_price)})
                  </p>
                  <span
                    className={`text-xs px-2 py-0.5 rounded-full ${
                      booking.full_payment_status === 'verified'
                        ? 'bg-green-500/10 text-green-400'
                        : booking.full_payment_status === 'uploaded'
                          ? 'bg-yellow-500/10 text-yellow-400'
                          : 'bg-slate-500/10 text-slate-400'
                    }`}
                  >
                    {booking.full_payment_status || 'pending'}
                  </span>
                </div>
                {booking.full_payment_receipt_path && (
                  <a
                    href={
                      supabase.storage
                        .from('customer-documents')
                        .getPublicUrl(booking.full_payment_receipt_path).data.publicUrl
                    }
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-xs text-violet-400 hover:text-violet-300 flex items-center gap-1 mb-2"
                  >
                    <Eye className="w-3 h-3" /> View Receipt
                  </a>
                )}
                {booking.full_payment_status === 'uploaded' && (
                  <button
                    onClick={handleVerifyFullPayment}
                    className="px-3 py-1.5 rounded-lg text-xs bg-green-500/10 text-green-400 hover:bg-green-500/20 transition-colors mt-2"
                  >
                    ✓ Verify Full Payment
                  </button>
                )}
                {/* Allow admin to upload full payment receipt on behalf of customer */}
                {['CONFIRMED', 'PICKUP'].includes(booking.status) &&
                  !booking.full_payment_receipt_path && (
                    <div className="mt-3 flex items-center gap-2">
                      <label className="flex items-center gap-2 text-xs text-slate-400 cursor-pointer">
                        <FileImage className="w-3.5 h-3.5" />
                        {fullPaymentFile ? fullPaymentFile.name : 'Upload receipt'}
                        <input
                          type="file"
                          accept="image/*,.pdf"
                          className="hidden"
                          onChange={(e) => setFullPaymentFile(e.target.files[0])}
                        />
                      </label>
                      {fullPaymentFile && (
                        <button
                          onClick={handleUploadFullPayment}
                          disabled={uploadingReceipt}
                          className="px-3 py-1 rounded-lg text-xs bg-violet-500/10 text-violet-300 hover:bg-violet-500/20"
                        >
                          {uploadingReceipt ? 'Uploading...' : 'Upload'}
                        </button>
                      )}
                    </div>
                  )}
              </div>
            </div>

            {/* Official Invoice */}
            {(booking.deposit_status === 'verified' ||
              booking.full_payment_status === 'verified') && (
              <div className="bg-violet-500/5 border border-violet-500/10 rounded-xl p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-white font-medium">Official Invoice / Receipt</p>
                    <p className="text-xs text-slate-500">Auto-generated company invoice</p>
                  </div>
                  <a
                    href={`/booking/${id}/invoice`}
                    target="_blank"
                    rel="noreferrer"
                    className="flex items-center gap-1.5 px-3 py-2 rounded-lg text-xs font-medium bg-violet-500/20 text-violet-300 hover:bg-violet-500/30 transition-colors whitespace-nowrap"
                  >
                    <Eye className="w-3.5 h-3.5" /> View Invoice
                  </a>
                </div>
              </div>
            )}
          </div>

          {/* Documents */}
          <div className="glass-card">
            <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
              <Shield className="w-4 h-4" /> Identity Documents
            </h3>
            {documents.length === 0 ? (
              <p className="text-sm text-slate-500">No documents uploaded yet.</p>
            ) : (
              <div className="space-y-3">
                {documents.map((doc) => (
                  <div key={doc.id} className="bg-white/[0.02] rounded-xl p-4">
                    <div className="flex items-center justify-between mb-2">
                      <div className="flex items-center gap-2">
                        <FileCheck className="w-4 h-4 text-violet-400" />
                        <span className="text-sm text-white">Driving Licence</span>
                      </div>
                      {doc.verified_at ? (
                        <span className="flex items-center gap-1 text-xs text-green-400">
                          <CheckCircle className="w-3.5 h-3.5" /> Verified
                        </span>
                      ) : (
                        <button
                          onClick={() => handleVerify(doc.id)}
                          className="px-3 py-1 rounded-lg text-xs bg-violet-500/10 text-violet-300 hover:bg-violet-500/20 transition-colors"
                        >
                          Verify
                        </button>
                      )}
                    </div>
                    <div className="grid grid-cols-2 gap-3 text-xs">
                      {doc.ic_number && (
                        <div>
                          <p className="text-slate-500">IC No.</p>
                          <p className="text-slate-200">{maskSensitive(doc.ic_number)}</p>
                        </div>
                      )}
                      <div>
                        <p className="text-slate-500">Expiry</p>
                        <p className="text-slate-200">{formatDate(doc.licence_expiry)}</p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Sidebar - Payment & Audit */}
        <div className="space-y-6">
          {/* Payment */}
          {payment && (
            <div className="glass-card">
              <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4">
                Payment Record
              </h3>
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-slate-500">Type</span>
                  <span className="text-slate-300 capitalize">
                    {payment.payment_type || 'deposit'}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-500">Amount</span>
                  <span className="text-white">{formatMYR(payment.amount)}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-500">Method</span>
                  <span className="text-slate-300 capitalize">{payment.payment_method}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-500">Status</span>
                  <span className="text-green-400 capitalize">{payment.status}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-500">Reference</span>
                  <span className="text-xs font-mono text-slate-300">
                    {payment.reference_number}
                  </span>
                </div>
              </div>
            </div>
          )}

          {/* Audit Log */}
          <div className="glass-card">
            <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
              <Eye className="w-4 h-4" /> Audit Log
            </h3>
            {auditLogs.length === 0 ? (
              <p className="text-xs text-slate-500">No audit entries.</p>
            ) : (
              <div className="space-y-3 max-h-64 overflow-y-auto">
                {auditLogs.map((log) => (
                  <div key={log.id} className="flex items-start gap-2 text-xs">
                    <Clock className="w-3.5 h-3.5 text-slate-600 mt-0.5 shrink-0" />
                    <div>
                      <p className="text-slate-300">{log.action.replace('_', ' ')}</p>
                      <p className="text-slate-600">
                        {log.bubatrent_booking_profiles?.display_name || 'Admin'} ·{' '}
                        {formatDateTime(log.created_at)}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Timeline */}
          <div className="glass-card">
            <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4">
              Timeline
            </h3>
            <div className="space-y-2 text-xs">
              <div className="flex justify-between">
                <span className="text-slate-500">Created</span>
                <span className="text-slate-300">{formatDateTime(booking.created_at)}</span>
              </div>
              {booking.updated_at && (
                <div className="flex justify-between">
                  <span className="text-slate-500">Updated</span>
                  <span className="text-slate-300">{formatDateTime(booking.updated_at)}</span>
                </div>
              )}
              {booking.actual_return_date && (
                <div className="flex justify-between">
                  <span className="text-slate-500">Returned</span>
                  <span className="text-emerald-400">{formatDate(booking.actual_return_date)}</span>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </AdminLayout>
  );
}

import { useState, useEffect } from 'react';
import AdminLayout from '../../components/AdminLayout';
import { useAuth } from '../../hooks/useAuth';
import { useFleet } from '../../hooks/useFleet';
import { supabase } from '../../lib/supabase';
import { useToast } from '../../components/Toast';
import LoadingSpinner from '../../components/LoadingSpinner';
import EmptyState from '../../components/EmptyState';
import { formatDate } from '../../utils/dates';
import {
  FileCheck,
  CheckCircle,
  XCircle,
  Clock,
  Loader2,
  ArrowRight,
  ChevronDown,
  ChevronUp,
  ShieldAlert,
} from 'lucide-react';

const STATUS_STYLE = {
  PENDING: 'bg-amber-500/10 text-amber-400 border-amber-500/20',
  APPROVED: 'bg-green-500/10 text-green-400 border-green-500/20',
  REJECTED: 'bg-red-500/10 text-red-400 border-red-500/20',
};

const FIELD_LABELS = {
  ic_number: 'IC Number',
  address_line1: 'Address Line 1',
  address_line2: 'Address Line 2',
  city: 'City',
  state: 'State',
  postcode: 'Postcode',
  licence_expiry: 'Licence Expiry',
  is_verified: 'Verification Status',
  verified_at: 'Verified At',
  verified_by: 'Verified By',
};

export default function ChangeRequests() {
  const { user, isSuperAdmin } = useAuth();
  const { isSuperGroup, activeFleetId } = useFleet();
  const toast = useToast();
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [expandedId, setExpandedId] = useState(null);
  const [actionLoading, setActionLoading] = useState(null);
  const [filter, setFilter] = useState('PENDING');
  const [rejectModal, setRejectModal] = useState(null);

  useEffect(() => {
    fetchRequests();
  }, [filter, activeFleetId]);

  async function fetchRequests() {
    setLoading(true);
    let query = supabase
      .from('bubatrent_booking_change_requests')
      .select(
        '*, bubatrent_booking_fleet_groups(name), bubatrent_booking_profiles!customer_id(display_name, username)'
      )
      .order('created_at', { ascending: false });

    if (filter !== 'ALL') {
      query = query.eq('status', filter);
    }

    // Non-super-group admins only see their own group's requests
    if (!isSuperAdmin || !isSuperGroup) {
      query = query.eq('fleet_group_id', activeFleetId);
    }

    const { data, error } = await query;
    if (error) console.error('Error fetching change requests:', error);
    setRequests(data || []);
    setLoading(false);
  }

  async function handleApprove(request) {
    setActionLoading(request.id);
    try {
      // Apply the changes to the customer profile
      const changes = request.changes;
      const updates = {};
      Object.keys(changes).forEach((field) => {
        updates[field] = changes[field].new;
      });

      const { error: profileErr } = await supabase
        .from('bubatrent_booking_profiles')
        .update(updates)
        .eq('id', request.customer_id);
      if (profileErr) throw profileErr;

      // Mark request as approved
      const { error: reqErr } = await supabase
        .from('bubatrent_booking_change_requests')
        .update({
          status: 'APPROVED',
          reviewed_by: user.id,
          reviewed_at: new Date().toISOString(),
        })
        .eq('id', request.id);
      if (reqErr) throw reqErr;

      // Audit log
      await supabase.from('bubatrent_booking_audit_logs').insert({
        admin_id: user.id,
        action: 'APPROVE_CHANGE_REQUEST',
        resource_type: 'change_request',
        resource_id: request.id,
        details: { customer_id: request.customer_id, changes },
      });

      toast.success('Change request approved — customer record updated');
      await fetchRequests();
    } catch (err) {
      toast.error(err.message);
    } finally {
      setActionLoading(null);
    }
  }

  async function handleReject(requestId, reason) {
    setActionLoading(requestId);
    try {
      const { error } = await supabase
        .from('bubatrent_booking_change_requests')
        .update({
          status: 'REJECTED',
          rejection_reason: reason,
          reviewed_by: user.id,
          reviewed_at: new Date().toISOString(),
        })
        .eq('id', requestId);
      if (error) throw error;

      await supabase.from('bubatrent_booking_audit_logs').insert({
        admin_id: user.id,
        action: 'REJECT_CHANGE_REQUEST',
        resource_type: 'change_request',
        resource_id: requestId,
        details: { reason },
      });

      toast.success('Change request rejected');
      setRejectModal(null);
      await fetchRequests();
    } catch (err) {
      toast.error(err.message);
    } finally {
      setActionLoading(null);
    }
  }

  return (
    <AdminLayout title="Change Requests">
      <p className="text-sm text-slate-400 mb-4">
        {isSuperAdmin && isSuperGroup
          ? 'Review and approve/reject sensitive customer data changes from all groups.'
          : 'Track changes you submitted for Super Group approval.'}
      </p>

      {/* Filter tabs */}
      <div className="flex gap-2 mb-6">
        {['PENDING', 'APPROVED', 'REJECTED', 'ALL'].map((s) => (
          <button
            key={s}
            onClick={() => setFilter(s)}
            className={`px-3 py-1.5 rounded-xl text-xs font-medium transition-all ${
              filter === s
                ? 'bg-violet-500/20 text-violet-300 border border-violet-500/30'
                : 'glass-card text-slate-400 hover:text-white'
            }`}
          >
            {s === 'ALL'
              ? 'All'
              : s === 'PENDING'
                ? '⏳ Pending'
                : s === 'APPROVED'
                  ? '✅ Approved'
                  : '❌ Rejected'}
          </button>
        ))}
      </div>

      {loading ? (
        <LoadingSpinner />
      ) : requests.length === 0 ? (
        <EmptyState
          icon={FileCheck}
          title={filter === 'PENDING' ? 'No pending requests' : 'No change requests'}
          description={
            filter === 'PENDING'
              ? 'All change requests have been processed.'
              : 'No change requests match this filter.'
          }
        />
      ) : (
        <div className="space-y-3">
          {requests.map((req) => {
            const isExpanded = expandedId === req.id;
            const changes = req.changes || {};
            const changedFields = Object.keys(changes);
            const customer = req.bubatrent_booking_profiles;
            const group = req.bubatrent_booking_fleet_groups;

            return (
              <div key={req.id} className="glass-card">
                <div
                  className="flex items-center justify-between cursor-pointer"
                  onClick={() => setExpandedId(isExpanded ? null : req.id)}
                >
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="text-sm text-white font-semibold">
                        {customer?.display_name || customer?.username || 'Unknown'}
                      </span>
                      <span className="text-[10px] text-slate-500">•</span>
                      <span className="text-[10px] text-slate-500">{group?.name}</span>
                      <span
                        className={`px-2 py-0.5 rounded-full text-[10px] font-semibold border ${STATUS_STYLE[req.status]}`}
                      >
                        {req.status}
                      </span>
                    </div>
                    <p className="text-xs text-slate-500 mt-0.5">
                      {changedFields.length} field{changedFields.length !== 1 ? 's' : ''} changed •{' '}
                      {new Date(req.created_at).toLocaleString()}
                    </p>
                  </div>
                  {isExpanded ? (
                    <ChevronUp className="w-4 h-4 text-slate-500" />
                  ) : (
                    <ChevronDown className="w-4 h-4 text-slate-500" />
                  )}
                </div>

                {isExpanded && (
                  <div className="mt-4 space-y-3 animate-fade-in">
                    {/* Diff view */}
                    <div className="bg-white/[0.02] rounded-xl p-3 space-y-2">
                      <h4 className="text-xs font-semibold text-slate-500 uppercase">Changes</h4>
                      {changedFields.map((field) => (
                        <div key={field} className="flex items-center gap-2 text-sm">
                          <span className="text-slate-400 font-medium min-w-[120px]">
                            {FIELD_LABELS[field] || field}
                          </span>
                          <span className="text-red-400/70 line-through text-xs">
                            {String(changes[field].old || '—')}
                          </span>
                          <ArrowRight className="w-3 h-3 text-slate-600" />
                          <span className="text-green-400 text-xs font-medium">
                            {String(changes[field].new || '—')}
                          </span>
                        </div>
                      ))}
                    </div>

                    {/* Rejection reason */}
                    {req.status === 'REJECTED' && req.rejection_reason && (
                      <div className="bg-red-500/5 border border-red-500/20 rounded-xl p-3">
                        <p className="text-xs text-red-300 font-semibold">Rejection Reason:</p>
                        <p className="text-xs text-slate-300 mt-1">{req.rejection_reason}</p>
                      </div>
                    )}

                    {/* Actions — only for super admin + pending */}
                    {isSuperAdmin && isSuperGroup && req.status === 'PENDING' && (
                      <div className="flex gap-2 pt-2 border-t border-white/5">
                        <button
                          onClick={() => handleApprove(req)}
                          disabled={actionLoading === req.id}
                          className="flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-xs font-medium bg-green-500/10 text-green-400 hover:bg-green-500/20 border border-green-500/20 transition-all disabled:opacity-50"
                        >
                          {actionLoading === req.id ? (
                            <Loader2 className="w-3.5 h-3.5 animate-spin" />
                          ) : (
                            <CheckCircle className="w-3.5 h-3.5" />
                          )}
                          Approve & Apply
                        </button>
                        <button
                          onClick={() => setRejectModal({ id: req.id, reason: '' })}
                          className="flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-xs font-medium bg-red-500/10 text-red-400 hover:bg-red-500/20 border border-red-500/20 transition-all"
                        >
                          <XCircle className="w-3.5 h-3.5" /> Reject
                        </button>
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Reject Modal */}
      {rejectModal && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm"
          onClick={() => setRejectModal(null)}
        >
          <div
            className="glass-card w-full max-w-md animate-fade-in"
            onClick={(e) => e.stopPropagation()}
          >
            <h3 className="text-lg font-semibold text-white mb-4">Reject Change Request</h3>
            <div>
              <label className="input-label">Rejection Reason *</label>
              <textarea
                value={rejectModal.reason}
                onChange={(e) => setRejectModal({ ...rejectModal, reason: e.target.value })}
                className="input-field min-h-[80px]"
                placeholder="Explain why this change is being rejected..."
              />
            </div>
            <div className="flex gap-3 mt-4">
              <button onClick={() => setRejectModal(null)} className="btn-secondary flex-1">
                Cancel
              </button>
              <button
                onClick={() => handleReject(rejectModal.id, rejectModal.reason)}
                disabled={!rejectModal.reason?.trim() || actionLoading === rejectModal.id}
                className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-sm font-medium bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/20 transition-all disabled:opacity-50"
              >
                {actionLoading === rejectModal.id ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : null}
                Reject
              </button>
            </div>
          </div>
        </div>
      )}
    </AdminLayout>
  );
}

import { useState, useEffect } from 'react';
import { useAuth } from '../../hooks/useAuth';
import { useFleet } from '../../hooks/useFleet';
import {
  useAdminCustomers,
  updateUserRole,
  getCustomerBookings,
  verifyCustomer,
  unverifyCustomer,
  rejectVerification,
} from '../../hooks/useAdmin';
import AdminLayout from '../../components/AdminLayout';
import BookingStatusBadge from '../../components/BookingStatusBadge';
import LoadingSpinner from '../../components/LoadingSpinner';
import EmptyState from '../../components/EmptyState';
import { formatDate } from '../../utils/dates';
import { formatMYR } from '../../utils/pricing';
import {
  Search,
  Users,
  Shield,
  ShieldOff,
  Mail,
  Phone,
  CalendarDays,
  ChevronDown,
  ChevronUp,
  X,
  AlertTriangle,
  CheckCircle,
  Clock,
  FileCheck,
  Wallet,
  Edit3,
  Upload,
  FileImage,
  Loader2,
  UserPlus,
} from 'lucide-react';
import { useToast } from '../../components/Toast';
import { supabase } from '../../lib/supabase';
import { uploadFileRobust } from '../../lib/uploadHelper';

const ROLE_OPTIONS = ['ALL', 'customer', 'admin', 'super_admin'];

export default function Customers() {
  const { user, isSuperAdmin } = useAuth();
  const { activeFleetId, isSuperGroup, canAccessSensitiveData, canWrite } = useFleet();
  const toast = useToast();
  const [search, setSearch] = useState('');
  const [roleFilter, setRoleFilter] = useState('ALL');
  const [verificationFilter, setVerificationFilter] = useState('ALL');
  const [debouncedSearch, setDebouncedSearch] = useState('');
  const [expandedId, setExpandedId] = useState(null);
  const [bookings, setBookings] = useState([]);
  const [bookingsLoading, setBookingsLoading] = useState(false);
  const [roleChanging, setRoleChanging] = useState(null);
  const [confirmRole, setConfirmRole] = useState(null);
  const [verifyChanging, setVerifyChanging] = useState(null);
  const [rejectingId, setRejectingId] = useState(null);
  const [rejectReason, setRejectReason] = useState('');
  const [showRejectConfirm, setShowRejectConfirm] = useState(null);
  const [deductAmount, setDeductAmount] = useState('');
  const [deductReason, setDeductReason] = useState('');
  const [deductingId, setDeductingId] = useState(null);

  // Edit customer details
  const [editingCustomer, setEditingCustomer] = useState(null);
  const [editForm, setEditForm] = useState({});
  const [editFiles, setEditFiles] = useState({ ic: null, licence: null });
  const [savingEdit, setSavingEdit] = useState(false);

  // Add credit
  const [addCreditForm, setAddCreditForm] = useState({});
  const [addingCredit, setAddingCredit] = useState(null);

  const STATES = [
    'Johor',
    'Kedah',
    'Kelantan',
    'Melaka',
    'Negeri Sembilan',
    'Pahang',
    'Perak',
    'Perlis',
    'Pulau Pinang',
    'Sabah',
    'Sarawak',
    'Selangor',
    'Terengganu',
    'W.P. Kuala Lumpur',
    'W.P. Labuan',
    'W.P. Putrajaya',
  ];

  // Debounce search input
  useEffect(() => {
    const timer = setTimeout(() => setDebouncedSearch(search), 300);
    return () => clearTimeout(timer);
  }, [search]);

  const { customers, loading, refetch } = useAdminCustomers({
    search: debouncedSearch,
    role: roleFilter,
    fleetId: activeFleetId,
    verification: verificationFilter !== 'ALL' ? verificationFilter : undefined,
  });

  async function handleExpand(customerId) {
    if (expandedId === customerId) {
      setExpandedId(null);
      setBookings([]);
      return;
    }
    setExpandedId(customerId);
    setBookingsLoading(true);
    try {
      const data = await getCustomerBookings(customerId);
      setBookings(data);
    } catch {
      setBookings([]);
    } finally {
      setBookingsLoading(false);
    }
  }

  async function handleRoleChange(customerId, newRole) {
    if (customerId === user?.id) return;
    if (!isSuperAdmin) return; // Only super admins can change roles
    setRoleChanging(customerId);
    try {
      await updateUserRole(customerId, newRole, user.id);
      await refetch();
      setConfirmRole(null);
    } catch (err) {
      toast.error('Failed to update role: ' + err.message);
    } finally {
      setRoleChanging(null);
    }
  }

  async function handleVerifyToggle(customerId, currentlyVerified) {
    setVerifyChanging(customerId);
    try {
      if (currentlyVerified) {
        await unverifyCustomer(customerId, user.id);
        toast.success('Verification revoked');
      } else {
        await verifyCustomer(customerId, user.id);
        toast.success('Customer verified!');
      }
      await refetch();
    } catch (err) {
      toast.error('Failed: ' + err.message);
    } finally {
      setVerifyChanging(null);
    }
  }

  async function handleRejectVerification(customerId) {
    setRejectingId(customerId);
    try {
      await rejectVerification(customerId, user.id, rejectReason || 'Documents rejected by admin');
      toast.success('Verification rejected — customer must re-upload documents');
      await refetch();
      setShowRejectConfirm(null);
      setRejectReason('');
    } catch (err) {
      toast.error('Failed to reject: ' + err.message);
    } finally {
      setRejectingId(null);
    }
  }

  return (
    <AdminLayout title="Customer Management">
      {/* Filters */}
      <div className="flex flex-col gap-3 mb-6">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
          <input
            type="text"
            placeholder="Search by name, email, or phone..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="input-field !pl-10"
          />
        </div>
        <div className="flex flex-wrap items-center gap-3">
          <select
            value={roleFilter}
            onChange={(e) => setRoleFilter(e.target.value)}
            className="input-field !py-1.5 !px-3 text-xs w-40"
          >
            <option value="ALL">All Roles</option>
            <option value="customer">👤 Customer</option>
            <option value="admin">🛡️ Admin</option>
            <option value="super_admin">🟠 Super Admin</option>
          </select>
          {['ALL', 'verified', 'not_verified', 'pending'].map((v) => (
            <button
              key={v}
              onClick={() => setVerificationFilter(v)}
              className={`px-3 py-1.5 rounded-xl text-xs font-medium transition-all ${
                verificationFilter === v
                  ? 'bg-green-500/20 text-green-300 border border-green-500/30'
                  : 'bg-white/5 text-slate-400 hover:bg-white/10'
              }`}
            >
              {v === 'ALL'
                ? 'All Status'
                : v === 'verified'
                  ? '✅ Verified'
                  : v === 'not_verified'
                    ? '❌ Not Verified'
                    : '⏳ Pending'}
            </button>
          ))}
        </div>
      </div>

      {/* Stats bar + Action buttons */}
      <div className="flex items-center justify-between mb-6">
        <div className="flex gap-4 text-sm text-slate-400">
          <span>
            {customers.length} user{customers.length !== 1 ? 's' : ''} found
          </span>
          <span>•</span>
          <span>
            {customers.filter((c) => c.role === 'admin').length} admin
            {customers.filter((c) => c.role === 'admin').length !== 1 ? 's' : ''}
          </span>
        </div>
        <div className="flex gap-2">
          <a
            href="/admin/customers/create"
            className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-medium bg-violet-500/20 text-violet-300 hover:bg-violet-500/30 border border-violet-500/30 transition-all"
          >
            <UserPlus className="w-3.5 h-3.5" /> Create Customer
          </a>
          <a
            href="/admin/bookings/create"
            className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-medium bg-green-500/20 text-green-300 hover:bg-green-500/30 border border-green-500/30 transition-all"
          >
            <CalendarDays className="w-3.5 h-3.5" /> Book for Customer
          </a>
        </div>
      </div>

      {/* Customer List */}
      {loading ? (
        <LoadingSpinner />
      ) : customers.length === 0 ? (
        <EmptyState
          icon={Users}
          title="No customers found"
          message={search ? 'Try a different search term' : 'No registered users yet'}
        />
      ) : (
        <div className="space-y-3">
          {customers.map((customer) => (
            <div key={customer.id} className="glass-card">
              {/* Main row */}
              <div
                className="flex items-center gap-4 cursor-pointer p-4 hover:bg-white/[0.02] transition-colors rounded-xl"
                onClick={() => handleExpand(customer.id)}
              >
                {/* Avatar */}
                <div
                  className={`w-10 h-10 rounded-full flex items-center justify-center shrink-0 ${
                    customer.role === 'super_admin'
                      ? 'bg-gradient-to-br from-amber-500 to-orange-600'
                      : customer.role === 'admin'
                        ? 'bg-gradient-to-br from-violet-500 to-indigo-600'
                        : 'bg-gradient-to-br from-slate-600 to-slate-700'
                  }`}
                >
                  <span className="text-white font-semibold text-sm">
                    {(customer.display_name || customer.username || '?')[0].toUpperCase()}
                  </span>
                </div>

                {/* Info */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <span className="font-medium text-white truncate">
                      {customer.display_name || 'Unnamed'}
                    </span>
                    <span
                      className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded-full ${
                        customer.role === 'super_admin'
                          ? 'bg-amber-500/20 text-amber-300'
                          : customer.role === 'admin'
                            ? 'bg-violet-500/20 text-violet-300'
                            : 'bg-slate-700/50 text-slate-400'
                      }`}
                    >
                      {customer.role === 'super_admin' ? 'SUPER ADMIN' : customer.role}
                    </span>
                    {customer.is_verified ? (
                      <span className="text-[10px] font-bold uppercase px-2 py-0.5 rounded-full bg-green-500/20 text-green-300 flex items-center gap-1">
                        <CheckCircle className="w-3 h-3" /> Verified
                      </span>
                    ) : customer.ic_number ? (
                      <span className="text-[10px] font-bold uppercase px-2 py-0.5 rounded-full bg-yellow-500/20 text-yellow-300 flex items-center gap-1">
                        <Clock className="w-3 h-3" /> Pending
                      </span>
                    ) : null}
                  </div>
                  <div className="flex items-center gap-3 text-xs text-slate-500 mt-0.5">
                    <span className="flex items-center gap-1 truncate">
                      <Mail className="w-3 h-3" /> {customer.username}
                    </span>
                    {customer.phone && (
                      <span className="flex items-center gap-1">
                        <Phone className="w-3 h-3" /> {customer.phone}
                      </span>
                    )}
                  </div>
                </div>

                {/* Booking count */}
                <div className="text-right shrink-0 hidden sm:block">
                  <div className="text-lg font-bold text-white">{customer.booking_count}</div>
                  <div className="text-[10px] text-slate-500 uppercase tracking-wide">Bookings</div>
                </div>

                {/* Joined date */}
                <div className="text-right shrink-0 hidden md:block">
                  <div className="text-xs text-slate-400">
                    {customer.created_at ? formatDate(customer.created_at) : '—'}
                  </div>
                  <div className="text-[10px] text-slate-500">Joined</div>
                </div>

                {/* Expand arrow */}
                <div className="shrink-0 text-slate-500">
                  {expandedId === customer.id ? (
                    <ChevronUp className="w-4 h-4" />
                  ) : (
                    <ChevronDown className="w-4 h-4" />
                  )}
                </div>
              </div>

              {/* Expanded detail */}
              {expandedId === customer.id && (
                <div className="border-t border-white/5 p-4 animate-fade-in">
                  <div className="flex flex-col lg:flex-row gap-6">
                    {/* Actions */}
                    <div className="lg:w-64 shrink-0 space-y-4">
                      <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wider">
                        Actions
                      </h4>

                      {/* Role management - Super Admin only */}
                      {customer.id === user?.id ? (
                        <p className="text-xs text-slate-500 italic">Cannot change your own role</p>
                      ) : !isSuperAdmin ? (
                        <p className="text-xs text-slate-500 italic">
                          Only Super Admins can manage roles
                        </p>
                      ) : confirmRole?.id === customer.id ? (
                        <div className="glass-card !p-3 border border-yellow-500/20">
                          <div className="flex items-center gap-2 text-yellow-400 text-xs mb-2">
                            <AlertTriangle className="w-3.5 h-3.5" />
                            <span className="font-medium">
                              Change role to: {confirmRole && confirmRole.newRole}
                            </span>
                          </div>
                          <div className="flex gap-2">
                            <button
                              onClick={() => handleRoleChange(customer.id, confirmRole.newRole)}
                              disabled={roleChanging === customer.id}
                              className="btn-primary text-xs !py-1.5 !px-3 flex-1"
                            >
                              {roleChanging === customer.id ? 'Updating...' : 'Confirm'}
                            </button>
                            <button
                              onClick={() => setConfirmRole(null)}
                              className="btn-secondary text-xs !py-1.5 !px-3"
                            >
                              <X className="w-3 h-3" />
                            </button>
                          </div>
                        </div>
                      ) : (
                        <div className="space-y-2">
                          {customer.role !== 'super_admin' && (
                            <button
                              onClick={() =>
                                setConfirmRole({ id: customer.id, newRole: 'super_admin' })
                              }
                              className="flex items-center gap-2 w-full px-3 py-2 rounded-xl text-sm font-medium bg-amber-500/10 text-amber-400 hover:bg-amber-500/20 border border-amber-500/20 transition-all"
                            >
                              <Shield className="w-4 h-4" /> Make Super Admin
                            </button>
                          )}
                          {customer.role !== 'admin' && (
                            <button
                              onClick={() =>
                                setConfirmRole({
                                  id: customer.id,
                                  newRole: customer.role === 'super_admin' ? 'admin' : 'admin',
                                })
                              }
                              className={`flex items-center gap-2 w-full px-3 py-2 rounded-xl text-sm font-medium transition-all ${
                                customer.role === 'super_admin'
                                  ? 'bg-red-500/10 text-red-400 hover:bg-red-500/20 border border-red-500/20'
                                  : 'bg-violet-500/10 text-violet-400 hover:bg-violet-500/20 border border-violet-500/20'
                              }`}
                            >
                              {customer.role === 'super_admin' ? (
                                <>
                                  <ShieldOff className="w-4 h-4" /> Demote to Admin
                                </>
                              ) : (
                                <>
                                  <Shield className="w-4 h-4" /> Make Admin
                                </>
                              )}
                            </button>
                          )}
                          {customer.role !== 'customer' && (
                            <button
                              onClick={() =>
                                setConfirmRole({ id: customer.id, newRole: 'customer' })
                              }
                              className="flex items-center gap-2 w-full px-3 py-2 rounded-xl text-sm font-medium bg-red-500/10 text-red-400 hover:bg-red-500/20 border border-red-500/20 transition-all"
                            >
                              <ShieldOff className="w-4 h-4" /> Remove All Admin Access
                            </button>
                          )}
                        </div>
                      )}

                      {/* Verification & Details */}
                      <>
                        <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mt-4">
                          Verification & Details
                        </h4>
                        {customer.ic_number || customer.licence_number ? (
                          <div className="space-y-2">
                            <div className="text-xs text-slate-400 space-y-1">
                              {customer.ic_number && (
                                <p>
                                  <span className="text-slate-500">IC:</span> {customer.ic_number}
                                </p>
                              )}
                              {customer.licence_expiry && (
                                <p>
                                  <span className="text-slate-500">Expiry:</span>{' '}
                                  {formatDate(customer.licence_expiry)}
                                </p>
                              )}
                              {customer.phone && (
                                <p>
                                  <span className="text-slate-500">Phone:</span> {customer.phone}
                                </p>
                              )}
                              {customer.address_line1 && (
                                <p>
                                  <span className="text-slate-500">Address:</span>{' '}
                                  {customer.address_line1}, {customer.city} {customer.state}
                                </p>
                              )}
                              {customer.gdl_license && customer.gdl_license !== 'NONE' && (
                                <p>
                                  <span className="text-slate-500">License Type:</span>{' '}
                                  <span className="text-amber-400">{customer.gdl_license}</span>
                                </p>
                              )}
                            </div>

                            {/* Verification Documents */}
                            <div className="mt-3">
                              <p className="text-[10px] font-semibold text-slate-500 uppercase tracking-wider mb-2">
                                Verification Documents
                              </p>
                              <div className="grid grid-cols-2 gap-2">
                                {/* IC Document */}
                                <div
                                  className={`rounded-xl border p-2 ${customer.ic_file_path ? 'border-green-500/20 bg-green-500/5' : 'border-red-500/20 bg-red-500/5'}`}
                                >
                                  <p className="text-[10px] text-slate-500 mb-1">IC Image</p>
                                  {customer.ic_file_path ? (
                                    <a
                                      href={
                                        supabase.storage
                                          .from('customer-documents')
                                          .getPublicUrl(customer.ic_file_path).data.publicUrl
                                      }
                                      target="_blank"
                                      rel="noopener noreferrer"
                                      className="block"
                                    >
                                      <img
                                        src={
                                          supabase.storage
                                            .from('customer-documents')
                                            .getPublicUrl(customer.ic_file_path).data.publicUrl
                                        }
                                        alt="IC Document"
                                        className="w-full h-20 object-cover rounded-lg hover:opacity-80 transition-opacity cursor-pointer"
                                        onError={(e) => {
                                          e.target.style.display = 'none';
                                          const fallback =
                                            e.target.parentElement.querySelector('.doc-fallback');
                                          if (fallback) fallback.style.display = 'flex';
                                        }}
                                      />
                                      <div className="doc-fallback hidden items-center justify-center gap-1 h-20 rounded-lg bg-green-500/10 text-xs text-green-400 hover:bg-green-500/20 transition-colors cursor-pointer">
                                        <FileImage className="w-4 h-4" /> Click to view
                                      </div>
                                    </a>
                                  ) : (
                                    <p className="text-[10px] text-red-400 flex items-center gap-1">
                                      <AlertTriangle className="w-3 h-3" /> Missing
                                    </p>
                                  )}
                                </div>
                                {/* Licence Document */}
                                <div
                                  className={`rounded-xl border p-2 ${customer.licence_file_path ? 'border-green-500/20 bg-green-500/5' : 'border-red-500/20 bg-red-500/5'}`}
                                >
                                  <p className="text-[10px] text-slate-500 mb-1">Driving Licence</p>
                                  {customer.licence_file_path ? (
                                    <a
                                      href={
                                        supabase.storage
                                          .from('customer-documents')
                                          .getPublicUrl(customer.licence_file_path).data.publicUrl
                                      }
                                      target="_blank"
                                      rel="noopener noreferrer"
                                      className="block"
                                    >
                                      <img
                                        src={
                                          supabase.storage
                                            .from('customer-documents')
                                            .getPublicUrl(customer.licence_file_path).data.publicUrl
                                        }
                                        alt="Licence Document"
                                        className="w-full h-20 object-cover rounded-lg hover:opacity-80 transition-opacity cursor-pointer"
                                        onError={(e) => {
                                          e.target.style.display = 'none';
                                          const fallback =
                                            e.target.parentElement.querySelector('.doc-fallback');
                                          if (fallback) fallback.style.display = 'flex';
                                        }}
                                      />
                                      <div className="doc-fallback hidden items-center justify-center gap-1 h-20 rounded-lg bg-green-500/10 text-xs text-green-400 hover:bg-green-500/20 transition-colors cursor-pointer">
                                        <FileImage className="w-4 h-4" /> Click to view
                                      </div>
                                    </a>
                                  ) : (
                                    <p className="text-[10px] text-red-400 flex items-center gap-1">
                                      <AlertTriangle className="w-3 h-3" /> Missing
                                    </p>
                                  )}
                                </div>
                              </div>
                              {(!customer.ic_file_path || !customer.licence_file_path) && (
                                <p className="text-[10px] text-amber-400 mt-1.5 flex items-center gap-1">
                                  <AlertTriangle className="w-3 h-3" />
                                  Some documents are missing. Use "Edit Customer Details" to upload.
                                </p>
                              )}
                            </div>

                            <button
                              onClick={() => handleVerifyToggle(customer.id, customer.is_verified)}
                              disabled={verifyChanging === customer.id}
                              className={`flex items-center gap-2 w-full px-3 py-2 rounded-xl text-sm font-medium transition-all ${
                                customer.is_verified
                                  ? 'bg-red-500/10 text-red-400 hover:bg-red-500/20 border border-red-500/20'
                                  : 'bg-green-500/10 text-green-400 hover:bg-green-500/20 border border-green-500/20'
                              }`}
                            >
                              {verifyChanging === customer.id ? (
                                'Updating...'
                              ) : customer.is_verified ? (
                                <>
                                  <ShieldOff className="w-4 h-4" /> Revoke Verification
                                </>
                              ) : (
                                <>
                                  <FileCheck className="w-4 h-4" /> Verify Customer
                                </>
                              )}
                            </button>

                            {/* Reject Verification — only for pending (not verified, docs exist) */}
                            {!customer.is_verified &&
                              customer.ic_number &&
                              customer.ic_file_path &&
                              (showRejectConfirm === customer.id ? (
                                <div className="glass-card !p-3 border border-red-500/20 mt-2 space-y-2">
                                  <p className="text-xs text-red-400 font-medium">
                                    Reject verification? Customer must re-upload all documents.
                                  </p>
                                  <input
                                    type="text"
                                    placeholder="Reason (optional, e.g. blurry IC)"
                                    value={rejectReason}
                                    onChange={(e) => setRejectReason(e.target.value)}
                                    className="input-field !py-1.5 text-xs w-full"
                                  />
                                  <div className="flex gap-2">
                                    <button
                                      onClick={() => handleRejectVerification(customer.id)}
                                      disabled={rejectingId === customer.id}
                                      className="btn-primary text-xs !py-1.5 !px-3 flex-1 !bg-red-600 hover:!bg-red-700"
                                    >
                                      {rejectingId === customer.id
                                        ? 'Rejecting...'
                                        : 'Confirm Reject'}
                                    </button>
                                    <button
                                      onClick={() => {
                                        setShowRejectConfirm(null);
                                        setRejectReason('');
                                      }}
                                      className="btn-secondary text-xs !py-1.5 !px-3"
                                    >
                                      <X className="w-3 h-3" />
                                    </button>
                                  </div>
                                </div>
                              ) : (
                                <button
                                  onClick={() => setShowRejectConfirm(customer.id)}
                                  className="flex items-center gap-2 w-full px-3 py-2 rounded-xl text-sm font-medium bg-red-500/10 text-red-400 hover:bg-red-500/20 border border-red-500/20 transition-all mt-2"
                                >
                                  <ShieldOff className="w-4 h-4" /> Reject & Re-submit
                                </button>
                              ))}
                          </div>
                        ) : (
                          <p className="text-xs text-slate-500 italic">
                            No documents submitted yet
                          </p>
                        )}

                        {/* Edit Details Button */}
                        {editingCustomer === customer.id ? (
                          <div className="mt-3 space-y-3 glass-card !p-3 border border-violet-500/20">
                            <div className="flex items-center justify-between">
                              <h5 className="text-xs font-semibold text-violet-300 uppercase">
                                Edit Details
                              </h5>
                              <button
                                onClick={() => {
                                  setEditingCustomer(null);
                                  setEditFiles({ ic: null, licence: null });
                                }}
                                className="text-slate-500 hover:text-white"
                              >
                                <X className="w-4 h-4" />
                              </button>
                            </div>
                            <div className="grid grid-cols-1 gap-2">
                              <input
                                type="text"
                                value={editForm.ic_number || ''}
                                onChange={(e) =>
                                  setEditForm((f) => ({ ...f, ic_number: e.target.value }))
                                }
                                className="input-field !py-1.5 text-xs"
                                placeholder="IC Number (e.g. 901234-14-5678)"
                              />
                              <input
                                type="text"
                                value={editForm.phone || ''}
                                onChange={(e) =>
                                  setEditForm((f) => ({ ...f, phone: e.target.value }))
                                }
                                className="input-field !py-1.5 text-xs"
                                placeholder="Phone (e.g. +60191234567)"
                              />
                              <div>
                                <label className="text-[10px] text-slate-500 mb-1 block">
                                  Licence Expiry
                                </label>
                                <input
                                  type="date"
                                  value={editForm.licence_expiry || ''}
                                  onChange={(e) =>
                                    setEditForm((f) => ({ ...f, licence_expiry: e.target.value }))
                                  }
                                  className="input-field !py-1.5 text-xs"
                                />
                              </div>
                              <input
                                type="text"
                                value={editForm.address_line1 || ''}
                                onChange={(e) =>
                                  setEditForm((f) => ({ ...f, address_line1: e.target.value }))
                                }
                                className="input-field !py-1.5 text-xs"
                                placeholder="Address Line 1"
                              />
                              <input
                                type="text"
                                value={editForm.address_line2 || ''}
                                onChange={(e) =>
                                  setEditForm((f) => ({ ...f, address_line2: e.target.value }))
                                }
                                className="input-field !py-1.5 text-xs"
                                placeholder="Address Line 2 (optional)"
                              />
                              <div className="grid grid-cols-2 gap-2">
                                <input
                                  type="text"
                                  value={editForm.city || ''}
                                  onChange={(e) =>
                                    setEditForm((f) => ({ ...f, city: e.target.value }))
                                  }
                                  className="input-field !py-1.5 text-xs"
                                  placeholder="City"
                                />
                                <select
                                  value={editForm.state || ''}
                                  onChange={(e) =>
                                    setEditForm((f) => ({ ...f, state: e.target.value }))
                                  }
                                  className="input-field !py-1.5 text-xs"
                                >
                                  <option value="">State</option>
                                  {STATES.map((s) => (
                                    <option key={s} value={s}>
                                      {s}
                                    </option>
                                  ))}
                                </select>
                              </div>
                              <input
                                type="text"
                                value={editForm.postcode || ''}
                                onChange={(e) =>
                                  setEditForm((f) => ({ ...f, postcode: e.target.value }))
                                }
                                className="input-field !py-1.5 text-xs"
                                placeholder="Postcode"
                              />
                            </div>

                            {/* Document uploads */}
                            <div className="space-y-2">
                              <div>
                                <label className="text-[10px] text-slate-500 mb-1 block">
                                  IC Image (auto-verified)
                                </label>
                                <label className="flex items-center gap-2 px-3 py-2 rounded-xl text-xs bg-white/5 border border-white/10 cursor-pointer hover:bg-white/10 transition-colors">
                                  <FileImage className="w-3.5 h-3.5 text-slate-400" />
                                  <span className="text-slate-300 truncate">
                                    {editFiles.ic?.name || 'Choose IC image...'}
                                  </span>
                                  <input
                                    type="file"
                                    accept="image/*,.pdf"
                                    className="hidden"
                                    onChange={(e) =>
                                      setEditFiles((f) => ({ ...f, ic: e.target.files[0] }))
                                    }
                                  />
                                </label>
                              </div>
                              <div>
                                <label className="text-[10px] text-slate-500 mb-1 block">
                                  Licence Image (auto-verified)
                                </label>
                                <label className="flex items-center gap-2 px-3 py-2 rounded-xl text-xs bg-white/5 border border-white/10 cursor-pointer hover:bg-white/10 transition-colors">
                                  <FileImage className="w-3.5 h-3.5 text-slate-400" />
                                  <span className="text-slate-300 truncate">
                                    {editFiles.licence?.name || 'Choose licence image...'}
                                  </span>
                                  <input
                                    type="file"
                                    accept="image/*,.pdf"
                                    className="hidden"
                                    onChange={(e) =>
                                      setEditFiles((f) => ({ ...f, licence: e.target.files[0] }))
                                    }
                                  />
                                </label>
                              </div>
                            </div>

                            <button
                              disabled={savingEdit}
                              onClick={async () => {
                                setSavingEdit(true);
                                console.log('[EditSave] Starting save...');
                                try {
                                  const SENSITIVE_FIELDS = [
                                    'ic_number',
                                    'address_line1',
                                    'address_line2',
                                    'city',
                                    'state',
                                    'postcode',
                                    'licence_expiry',
                                  ];

                                  const directUpdates = {};
                                  const sensitiveChanges = {};

                                  // Categorize changes into sensitive vs non-sensitive
                                  if (editForm.phone && editForm.phone !== (customer.phone || ''))
                                    directUpdates.phone = editForm.phone;

                                  SENSITIVE_FIELDS.forEach((field) => {
                                    if (
                                      editForm[field] !== undefined &&
                                      editForm[field] !== (customer[field] || '')
                                    ) {
                                      sensitiveChanges[field] = {
                                        old: customer[field] || null,
                                        new: editForm[field],
                                      };
                                    }
                                  });
                                  console.log(
                                    '[EditSave] Direct updates:',
                                    Object.keys(directUpdates),
                                    'Sensitive:',
                                    Object.keys(sensitiveChanges)
                                  );

                                  // Upload files if provided
                                  const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB for mobile camera photos

                                  if (editFiles.ic) {
                                    if (editFiles.ic.size > MAX_FILE_SIZE)
                                      throw new Error(
                                        `IC file too large (${(editFiles.ic.size / 1024 / 1024).toFixed(1)}MB). Max 10MB.`
                                      );
                                    console.log('[EditSave] Uploading IC...');
                                    const ext =
                                      editFiles.ic.name.split('.').pop()?.toLowerCase() || 'jpg';
                                    const path = `${customer.id}/ic_admin_${Date.now()}.${ext}`;

                                    const { error: upErr } = await uploadFileRobust(
                                      'customer-documents',
                                      path,
                                      editFiles.ic,
                                      toast
                                    );
                                    if (upErr)
                                      throw new Error(`IC upload failed: ${upErr.message}`);

                                    console.log('[EditSave] IC uploaded to:', path);
                                    sensitiveChanges.ic_file_path = {
                                      old: customer.ic_file_path || null,
                                      new: path,
                                    };
                                  }

                                  if (editFiles.licence) {
                                    if (editFiles.licence.size > MAX_FILE_SIZE)
                                      throw new Error(
                                        `Licence file too large (${(editFiles.licence.size / 1024 / 1024).toFixed(1)}MB). Max 10MB.`
                                      );
                                    console.log('[EditSave] Uploading licence...');
                                    const ext =
                                      editFiles.licence.name.split('.').pop()?.toLowerCase() ||
                                      'jpg';
                                    const path = `${customer.id}/licence_admin_${Date.now()}.${ext}`;

                                    const { error: upErr } = await uploadFileRobust(
                                      'customer-documents',
                                      path,
                                      editFiles.licence,
                                      toast
                                    );
                                    if (upErr)
                                      throw new Error(`Licence upload failed: ${upErr.message}`);

                                    console.log('[EditSave] Licence uploaded to:', path);
                                    sensitiveChanges.licence_file_path = {
                                      old: customer.licence_file_path || null,
                                      new: path,
                                    };
                                  }

                                  // Auto-verify if docs uploaded AND group is Super Group
                                  if ((editFiles.ic || editFiles.licence) && isSuperGroup) {
                                    directUpdates.is_verified = true;
                                    directUpdates.verified_at = new Date().toISOString();
                                    directUpdates.verified_by = user.id;
                                    console.log('[EditSave] Auto-verify (Super Group)');
                                  }

                                  if (
                                    Object.keys(directUpdates).length === 0 &&
                                    Object.keys(sensitiveChanges).length === 0
                                  ) {
                                    toast.error('No changes to save');
                                    setSavingEdit(false);
                                    return;
                                  }

                                  let messages = [];

                                  // Super Group bypasses approval for everything
                                  if (isSuperGroup) {
                                    console.log(
                                      '[EditSave] Super Group: applying all changes directly'
                                    );
                                    // Apply all changes directly
                                    const allUpdates = { ...directUpdates };
                                    Object.keys(sensitiveChanges).forEach((f) => {
                                      allUpdates[f] = sensitiveChanges[f].new;
                                    });
                                    console.log(
                                      '[EditSave] Updating profile with:',
                                      Object.keys(allUpdates)
                                    );
                                    const { error } = await supabase
                                      .from('bubatrent_booking_profiles')
                                      .update(allUpdates)
                                      .eq('id', customer.id);
                                    if (error) {
                                      console.error('[EditSave] Profile update failed:', error);
                                      throw error;
                                    }
                                    console.log('[EditSave] Profile updated successfully');
                                    messages.push('Changes applied directly (Super Group)');
                                  } else {
                                    // Apply non-sensitive directly
                                    if (Object.keys(directUpdates).length > 0) {
                                      console.log('[EditSave] Updating non-sensitive fields');
                                      const { error } = await supabase
                                        .from('bubatrent_booking_profiles')
                                        .update(directUpdates)
                                        .eq('id', customer.id);
                                      if (error) {
                                        console.error(
                                          '[EditSave] Non-sensitive update failed:',
                                          error
                                        );
                                        throw error;
                                      }
                                      messages.push(
                                        `${Object.keys(directUpdates).length} field(s) updated`
                                      );
                                    }

                                    // Create change request for sensitive fields
                                    if (Object.keys(sensitiveChanges).length > 0) {
                                      console.log(
                                        '[EditSave] Creating change request for sensitive fields, fleetId:',
                                        activeFleetId
                                      );
                                      const { error: crErr } = await supabase
                                        .from('bubatrent_booking_change_requests')
                                        .insert({
                                          fleet_group_id: activeFleetId,
                                          customer_id: customer.id,
                                          requested_by: user.id,
                                          changes: sensitiveChanges,
                                        });
                                      if (crErr) {
                                        console.error('[EditSave] Change request failed:', crErr);
                                        throw crErr;
                                      }
                                      console.log('[EditSave] Change request created');
                                      messages.push(
                                        `${Object.keys(sensitiveChanges).length} sensitive field(s) sent for Super Group approval`
                                      );
                                    }
                                  }

                                  // Audit log
                                  console.log('[EditSave] Creating audit log');
                                  await supabase.from('bubatrent_booking_audit_logs').insert({
                                    admin_id: user.id,
                                    action: isSuperGroup
                                      ? 'UPDATE_CUSTOMER'
                                      : 'REQUEST_CUSTOMER_CHANGE',
                                    resource_type: 'profile',
                                    resource_id: customer.id,
                                    details: {
                                      direct_fields: Object.keys(directUpdates),
                                      sensitive_fields: Object.keys(sensitiveChanges),
                                      is_super_group: isSuperGroup,
                                    },
                                  });

                                  console.log('[EditSave] Done!', messages);
                                  toast.success(messages.join(' • '));
                                  setEditingCustomer(null);
                                  setEditFiles({ ic: null, licence: null });
                                  refetch();
                                } catch (err) {
                                  console.error('[EditSave] Error caught:', err);
                                  toast.error(err.message || 'Save failed');
                                } finally {
                                  setSavingEdit(false);
                                }
                              }}
                              className="flex items-center justify-center gap-2 w-full px-3 py-2 rounded-xl text-sm font-medium bg-violet-500/20 text-violet-300 hover:bg-violet-500/30 border border-violet-500/30 transition-all"
                            >
                              {savingEdit ? (
                                <>
                                  <Loader2 className="w-4 h-4 animate-spin" /> Saving...
                                </>
                              ) : (
                                <>
                                  <Edit3 className="w-4 h-4" /> Save Changes
                                </>
                              )}
                            </button>
                          </div>
                        ) : (
                          <button
                            onClick={() => {
                              setEditingCustomer(customer.id);
                              setEditForm({
                                ic_number: customer.ic_number || '',
                                phone: customer.phone || '',
                                licence_expiry: customer.licence_expiry || '',
                                address_line1: customer.address_line1 || '',
                                address_line2: customer.address_line2 || '',
                                city: customer.city || '',
                                state: customer.state || '',
                                postcode: customer.postcode || '',
                              });
                            }}
                            className="flex items-center gap-2 w-full px-3 py-2 rounded-xl text-sm font-medium bg-white/5 text-slate-300 hover:bg-white/10 border border-white/10 transition-all mt-2"
                          >
                            <Edit3 className="w-4 h-4" /> Edit Customer Details
                          </button>
                        )}
                      </>

                      {/* Deposit Credit */}
                      <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mt-4">
                        Deposit Credit
                      </h4>
                      <div className="flex items-center gap-2 mb-2">
                        <Wallet className="w-4 h-4 text-green-400" />
                        <span className="text-sm text-white font-semibold">
                          {formatMYR(customer.fleet_credit || 0)}
                        </span>
                      </div>
                      <div className="space-y-2">
                        {/* Add Credit */}
                        <div className="glass-card !p-3 border border-green-500/20 space-y-2">
                          <h5 className="text-[10px] font-semibold text-green-300 uppercase">
                            Add Credit
                          </h5>
                          <input
                            type="number"
                            min="0"
                            step="0.01"
                            value={expandedId === customer.id ? addCreditForm.amount || '' : ''}
                            onChange={(e) =>
                              setAddCreditForm((f) => ({ ...f, amount: e.target.value }))
                            }
                            className="input-field !py-1.5 text-xs"
                            placeholder="Amount (RM)"
                          />
                          <input
                            type="text"
                            value={expandedId === customer.id ? addCreditForm.reason || '' : ''}
                            onChange={(e) =>
                              setAddCreditForm((f) => ({ ...f, reason: e.target.value }))
                            }
                            className="input-field !py-1.5 text-xs"
                            placeholder="Reason (e.g. manual payment)"
                          />
                          <div>
                            <label className="text-[10px] text-slate-500 mb-1 block">
                              Transaction Date *
                            </label>
                            <input
                              type="date"
                              value={expandedId === customer.id ? addCreditForm.txDate || '' : ''}
                              onChange={(e) =>
                                setAddCreditForm((f) => ({ ...f, txDate: e.target.value }))
                              }
                              className="input-field !py-1.5 text-xs"
                            />
                          </div>
                          <div>
                            <label className="text-[10px] text-slate-500 mb-1 block">
                              Transfer Receipt (proof) *
                            </label>
                            <label className="flex items-center gap-2 px-3 py-2 rounded-xl text-xs bg-white/5 border border-white/10 cursor-pointer hover:bg-white/10 transition-colors">
                              <FileImage className="w-3.5 h-3.5 text-slate-400" />
                              <span className="text-slate-300 truncate">
                                {addCreditForm.receipt?.name || 'Upload receipt...'}
                              </span>
                              <input
                                type="file"
                                accept="image/*,.pdf"
                                className="hidden"
                                onChange={(e) =>
                                  setAddCreditForm((f) => ({ ...f, receipt: e.target.files[0] }))
                                }
                              />
                            </label>
                          </div>
                          <button
                            disabled={addingCredit === customer.id}
                            onClick={async () => {
                              const amt = Number(addCreditForm.amount);
                              if (!amt || amt <= 0) {
                                toast.error('Enter a valid amount');
                                return;
                              }
                              if (!addCreditForm.txDate) {
                                toast.error('Transaction date is required');
                                return;
                              }
                              if (!addCreditForm.receipt) {
                                toast.error('Transfer receipt is required as proof');
                                return;
                              }
                              setAddingCredit(customer.id);
                              try {
                                // Upload receipt
                                const ext = addCreditForm.receipt.name.split('.').pop();
                                const receiptPath = `${customer.id}/credit_receipt_${Date.now()}.${ext}`;
                                const { error: upErr } = await uploadFileRobust(
                                  'customer-documents',
                                  receiptPath,
                                  addCreditForm.receipt,
                                  toast
                                );
                                if (upErr) throw upErr;

                                // Update credit balance
                                const newCredit = Number(customer.deposit_credit || 0) + amt;
                                const { error: dbErr } = await supabase
                                  .from('bubatrent_booking_profiles')
                                  .update({ deposit_credit: newCredit })
                                  .eq('id', customer.id);
                                if (dbErr) throw dbErr;

                                // Log transaction
                                await supabase
                                  .from('bubatrent_booking_credit_transactions')
                                  .insert({
                                    user_id: customer.id,
                                    amount: amt,
                                    type: 'added',
                                    description: addCreditForm.reason || 'Manual credit (admin)',
                                    admin_id: user.id,
                                    fleet_group_id: activeFleetId,
                                  });

                                // Audit log
                                await supabase.from('bubatrent_booking_audit_logs').insert({
                                  admin_id: user.id,
                                  action: 'ADD_CREDIT',
                                  resource_type: 'profile',
                                  resource_id: customer.id,
                                  details: {
                                    amount: amt,
                                    tx_date: addCreditForm.txDate,
                                    receipt_path: receiptPath,
                                  },
                                });

                                toast.success(`Added ${formatMYR(amt)} credit`);
                                setAddCreditForm({});
                                refetch();
                              } catch (err) {
                                toast.error(err.message);
                              } finally {
                                setAddingCredit(null);
                              }
                            }}
                            className="flex items-center gap-1 w-full px-3 py-2 rounded-xl text-xs font-medium bg-green-500/10 text-green-400 hover:bg-green-500/20 border border-green-500/20 transition-all"
                          >
                            {addingCredit === customer.id ? 'Adding...' : '+ Add Credit'}
                          </button>
                        </div>

                        {/* Deduct Credit */}
                        <div className="space-y-2">
                          <h5 className="text-[10px] font-semibold text-red-300 uppercase">
                            Deduct Credit
                          </h5>
                          <input
                            type="number"
                            min="0"
                            step="0.01"
                            value={deductAmount}
                            onChange={(e) => setDeductAmount(e.target.value)}
                            className="input-field !py-1.5 text-xs"
                            placeholder="Amount to deduct"
                          />
                          <input
                            type="text"
                            value={deductReason}
                            onChange={(e) => setDeductReason(e.target.value)}
                            className="input-field !py-1.5 text-xs"
                            placeholder="Reason (e.g. fine, damage)"
                          />
                          <button
                            onClick={async () => {
                              if (!deductAmount || Number(deductAmount) <= 0) {
                                toast.error('Enter a valid amount');
                                return;
                              }
                              if (Number(deductAmount) > Number(customer.deposit_credit || 0)) {
                                toast.error('Cannot deduct more than balance');
                                return;
                              }
                              setDeductingId(customer.id);
                              try {
                                const newCredit =
                                  Number(customer.deposit_credit || 0) - Number(deductAmount);
                                const { error: upErr } = await supabase
                                  .from('bubatrent_booking_profiles')
                                  .update({ deposit_credit: newCredit })
                                  .eq('id', customer.id);
                                if (upErr) throw upErr;
                                await supabase
                                  .from('bubatrent_booking_credit_transactions')
                                  .insert({
                                    user_id: customer.id,
                                    amount: -Number(deductAmount),
                                    type: 'deducted',
                                    description: deductReason || 'Admin deduction',
                                    admin_id: user.id,
                                    fleet_group_id: activeFleetId,
                                  });
                                toast.success(`Deducted ${formatMYR(deductAmount)}`);
                                setDeductAmount('');
                                setDeductReason('');
                                refetch();
                              } catch (err) {
                                toast.error(err.message);
                              } finally {
                                setDeductingId(null);
                              }
                            }}
                            disabled={deductingId === customer.id}
                            className="flex items-center gap-1 w-full px-3 py-2 rounded-xl text-xs font-medium bg-red-500/10 text-red-400 hover:bg-red-500/20 border border-red-500/20 transition-all"
                          >
                            {deductingId === customer.id ? 'Deducting...' : 'Deduct Credit'}
                          </button>
                        </div>
                      </div>
                    </div>

                    {/* Booking history */}
                    <div className="flex-1 min-w-0">
                      <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-3">
                        Booking History
                      </h4>
                      {bookingsLoading ? (
                        <LoadingSpinner />
                      ) : bookings.length === 0 ? (
                        <p className="text-sm text-slate-500 italic">No bookings yet</p>
                      ) : (
                        <div className="space-y-2">
                          {bookings.map((b) => (
                            <div
                              key={b.id}
                              className="flex items-center gap-3 p-3 rounded-xl bg-white/[0.02] hover:bg-white/[0.04] transition-colors"
                            >
                              {b.bubatrent_booking_cars?.image_url && (
                                <img
                                  src={b.bubatrent_booking_cars.image_url}
                                  alt={b.bubatrent_booking_cars.name}
                                  className="w-12 h-8 rounded-lg object-cover shrink-0"
                                />
                              )}
                              <div className="flex-1 min-w-0">
                                <div className="text-sm font-medium text-white truncate">
                                  {b.bubatrent_booking_cars?.name || 'Unknown Car'}
                                </div>
                                <div className="text-xs text-slate-500 flex items-center gap-1">
                                  <CalendarDays className="w-3 h-3" />
                                  {formatDate(b.pickup_date)} → {formatDate(b.return_date)}
                                </div>
                              </div>
                              <div className="text-right shrink-0">
                                <div className="text-sm font-medium text-white">
                                  {formatMYR(b.total_price)}
                                </div>
                                <BookingStatusBadge status={b.status} />
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </AdminLayout>
  );
}

import { Link } from 'react-router-dom';
import AdminLayout from '../../components/AdminLayout';
import { useAdminStats } from '../../hooks/useAdmin';
import { useFleet } from '../../hooks/useFleet';
import LoadingSpinner from '../../components/LoadingSpinner';
import { formatMYR } from '../../utils/pricing';
import { CalendarDays, Car, DollarSign, FileCheck, TrendingUp, Users, Receipt } from 'lucide-react';

// Static color maps — dynamic template literals like `bg-${color}-500/10`
// get purged by Tailwind in production builds.
const bgColorMap = {
  violet: 'bg-violet-500/10',
  green: 'bg-green-500/10',
  indigo: 'bg-indigo-500/10',
  yellow: 'bg-yellow-500/10',
  cyan: 'bg-cyan-500/10',
};
const textColorMap = {
  violet: 'text-violet-400',
  green: 'text-green-400',
  indigo: 'text-indigo-400',
  yellow: 'text-yellow-400',
  cyan: 'text-cyan-400',
};

export default function AdminDashboard() {
  const { activeFleetId, activeFleet } = useFleet();
  const { stats, loading } = useAdminStats(activeFleetId);

  if (loading)
    return (
      <AdminLayout title="Dashboard">
        <LoadingSpinner />
      </AdminLayout>
    );

  const cards = [
    {
      label: 'Total Bookings',
      value: stats?.totalBookings || 0,
      icon: CalendarDays,
      color: 'violet',
    },
    {
      label: 'Active Bookings',
      value: stats?.activeBookings || 0,
      icon: TrendingUp,
      color: 'green',
    },
