  const { isSuperGroup } = useFleet();
  const toast = useToast();
  const [groups, setGroups] = useState([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(null);
  const [modal, setModal] = useState(null); // { type, group, reason, notes }

  useEffect(() => {
    fetchGroups();
  }, []);

  async function fetchGroups() {
    setLoading(true);
    const { data } = await supabase
      .from('bubatrent_booking_fleet_groups')
      .select('*')
      .order('created_at', { ascending: true });
    setGroups(data || []);
    setLoading(false);
  }

  if (!isSuperAdmin || !isSuperGroup) {
    return (
      <AdminLayout title="Group Management">
        <div className="glass-card text-center">
          <ShieldAlert className="w-8 h-8 text-red-400 mx-auto mb-2" />
          <p className="text-slate-400">Only Super Group administrators can manage groups.</p>
        </div>
      </AdminLayout>
    );
  }

  async function handleAction(type, groupId, reason, notes) {
    setActionLoading(groupId);
    try {
      const updates = {};
      let auditAction = '';

      if (type === 'approve') {
        updates.status = 'VERIFIED';
        updates.verified_at = new Date().toISOString();
        updates.verified_by = user.id;
        updates.rejection_reason = null;
        auditAction = 'APPROVE_GROUP';
      } else if (type === 'reject') {
        updates.status = 'REJECTED';
        updates.rejection_reason = reason;
        auditAction = 'REJECT_GROUP';
      } else if (type === 'suspend') {
        updates.status = 'SUSPENDED';
        updates.suspended_at = new Date().toISOString();
        updates.suspended_by = user.id;
        updates.suspension_reason = reason;
        updates.suspension_notes = notes || null;
        auditAction = 'SUSPEND_GROUP';
      } else if (type === 'unsuspend') {
        updates.status = 'VERIFIED';
        updates.suspended_at = null;
        updates.suspended_by = null;
        updates.suspension_reason = null;
        updates.suspension_notes = null;
        auditAction = 'UNSUSPEND_GROUP';
      }

      const { error: upErr } = await supabase
        .from('bubatrent_booking_fleet_groups')
        .update(updates)
        .eq('id', groupId);
      if (upErr) throw upErr;

      // Audit log
      await supabase.from('bubatrent_booking_audit_logs').insert({
        admin_id: user.id,
        action: auditAction,
        resource_type: 'fleet_group',
        resource_id: groupId,
        details: { reason, notes, timestamp: new Date().toISOString() },
      });

      toast.success(
        `Group ${type === 'approve' ? 'approved' : type === 'reject' ? 'rejected' : type === 'suspend' ? 'suspended' : 'unsuspended'} successfully`
      );
      setModal(null);
      await fetchGroups();
    } catch (err) {
      toast.error(err.message);
    } finally {
      setActionLoading(null);
    }
  }

  return (
    <AdminLayout title="Group Management">
      <p className="text-sm text-slate-400 mb-6">
        Manage tenant groups — approve registrations, suspend for violations, and track status.
      </p>

      {loading ? (
        <LoadingSpinner />
      ) : (
        <div className="space-y-3">
          {groups.map((group) => {
            const badge = STATUS_BADGES[group.status] || STATUS_BADGES.PENDING_VERIFICATION;
            const BadgeIcon = badge.icon;
            const isSelf = group.is_super_group;

            return (
              <div key={group.id} className="glass-card">
                <div className="flex items-start justify-between gap-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-violet-500/10 flex items-center justify-center shrink-0">
                      <Building2 className="w-5 h-5 text-violet-400" />
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <h3 className="text-white font-semibold">{group.name}</h3>
                        {isSelf && (
                          <span className="px-2 py-0.5 rounded-full text-[10px] bg-violet-500/20 text-violet-300 border border-violet-500/20">
                            Super Group
                          </span>
                        )}
                      </div>
                      <p className="text-xs text-slate-500">
                        {group.slug} • Created {new Date(group.created_at).toLocaleDateString()}
                      </p>
                    </div>
                  </div>

                  <div className="flex items-center gap-2">
                    <span
                      className={`flex items-center gap-1 px-2.5 py-1 rounded-full text-[10px] font-semibold bg-${badge.color}-500/10 text-${badge.color}-400 border border-${badge.color}-500/20`}
                    >
                      <BadgeIcon className="w-3 h-3" />
                      {badge.label}
                    </span>
                  </div>
                </div>

                {/* Suspension info */}
                {group.status === 'SUSPENDED' && group.suspension_reason && (
                  <div className="mt-3 bg-red-500/5 border border-red-500/20 rounded-xl p-3 text-sm">
                    <p className="text-red-300 font-semibold text-xs">Suspension Reason:</p>
                    <p className="text-slate-300 text-xs mt-1">{group.suspension_reason}</p>
                    {group.suspension_notes && (
                      <p className="text-slate-500 text-[10px] mt-1">
                        Notes: {group.suspension_notes}
                      </p>
                    )}
                    <p className="text-slate-600 text-[10px] mt-1">
                      Suspended {new Date(group.suspended_at).toLocaleString()}
                    </p>
                  </div>
                )}

                {group.status === 'REJECTED' && group.rejection_reason && (
                  <div className="mt-3 bg-red-500/5 border border-red-500/20 rounded-xl p-3">
                    <p className="text-red-300 font-semibold text-xs">Rejection Reason:</p>
                    <p className="text-slate-300 text-xs mt-1">{group.rejection_reason}</p>
                  </div>
                )}

                {/* Actions — not for self (Super Group) */}
                {!isSelf && (
                  <div className="flex flex-wrap gap-2 mt-4 pt-3 border-t border-white/5">
                    {(group.status === 'PENDING_VERIFICATION' || group.status === 'REJECTED') && (
                      <button
                        onClick={() => handleAction('approve', group.id)}
                        disabled={actionLoading === group.id}
                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-xs font-medium bg-green-500/10 text-green-400 hover:bg-green-500/20 border border-green-500/20 transition-all"
                      >
                        <CheckCircle className="w-3.5 h-3.5" /> Approve
                      </button>
                    )}
                    {group.status === 'PENDING_VERIFICATION' && (
                      <button
                        onClick={() => setModal({ type: 'reject', group })}
                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-xs font-medium bg-red-500/10 text-red-400 hover:bg-red-500/20 border border-red-500/20 transition-all"
                      >
                        <XCircle className="w-3.5 h-3.5" /> Reject
                      </button>
                    )}
                    {group.status === 'VERIFIED' && (
                      <button
                        onClick={() => setModal({ type: 'suspend', group })}
                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-xs font-medium bg-amber-500/10 text-amber-400 hover:bg-amber-500/20 border border-amber-500/20 transition-all"
                      >
                        <Ban className="w-3.5 h-3.5" /> Suspend
                      </button>
                    )}
                    {group.status === 'SUSPENDED' && (
                      <button
                        onClick={() => setModal({ type: 'unsuspend', group })}
                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-xs font-medium bg-green-500/10 text-green-400 hover:bg-green-500/20 border border-green-500/20 transition-all"
                      >
                        <Undo2 className="w-3.5 h-3.5" /> Unsuspend
                      </button>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Action Modal */}
      {modal && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm"
          onClick={() => setModal(null)}
        >
          <div
            className="glass-card w-full max-w-md animate-fade-in"
            onClick={(e) => e.stopPropagation()}
          >
            <h3 className="text-lg font-semibold text-white mb-4 capitalize">{modal.type} Group</h3>
            <p className="text-sm text-slate-400 mb-3">
              {modal.type === 'reject' &&
                `Reject "${modal.group.name}" registration? This will block their access to sensitive data.`}
              {modal.type === 'suspend' &&
                `Suspend "${modal.group.name}"? This will immediately block all write operations and sensitive data access.`}
              {modal.type === 'unsuspend' &&
                `Unsuspend "${modal.group.name}"? This will restore their verified status.`}
            </p>
            <div className="space-y-3">
              <div>
                <label className="input-label">Reason *</label>
                <textarea
                  value={modal.reason || ''}
                  onChange={(e) => setModal({ ...modal, reason: e.target.value })}
                  className="input-field min-h-[80px]"
                  placeholder="Enter reason..."
                  required
                />
              </div>
              {modal.type === 'suspend' && (
                <div>
                  <label className="input-label">Notes (optional)</label>
                  <textarea
                    value={modal.notes || ''}
                    onChange={(e) => setModal({ ...modal, notes: e.target.value })}
                    className="input-field min-h-[60px]"
                    placeholder="Internal notes..."
                  />
                </div>
              )}
            </div>
            <div className="flex gap-3 mt-4">
              <button onClick={() => setModal(null)} className="btn-secondary flex-1">
                Cancel
              </button>
              <button
                onClick={() => handleAction(modal.type, modal.group.id, modal.reason, modal.notes)}
                disabled={!modal.reason?.trim() || actionLoading === modal.group.id}
                className={`flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-sm font-medium transition-all ${
                  modal.type === 'unsuspend'
                    ? 'bg-green-500/20 text-green-400 hover:bg-green-500/30 border border-green-500/20'
                    : 'bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/20'
                } disabled:opacity-50`}
              >
                {actionLoading === modal.group.id ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : null}
                {modal.type === 'reject'
                  ? 'Reject'
                  : modal.type === 'suspend'
                    ? 'Suspend Now'
                    : 'Unsuspend'}
              </button>
            </div>
          </div>
        </div>
      )}
    </AdminLayout>
  );
}

import { useState, useEffect } from 'react';
import AdminLayout from '../../components/AdminLayout';
import { useAuth } from '../../hooks/useAuth';
import { useFleet } from '../../hooks/useFleet';
import { supabase } from '../../lib/supabase';
import { useToast } from '../../components/Toast';
import LoadingSpinner from '../../components/LoadingSpinner';
import EmptyState from '../../components/EmptyState';
import {
  Users,
  UserPlus,
  Shield,
  ShieldCheck,
  Trash2,
  Loader2,
  Search,
  ChevronDown,
  X,
  Crown,
} from 'lucide-react';

const ROLE_CONFIG = {
  fleet_admin: {
    label: 'Fleet Admin',
    icon: ShieldCheck,
    color: 'violet',
    desc: 'Full management access',
  },
  fleet_staff: { label: 'Staff', icon: Shield, color: 'slate', desc: 'View & limited actions' },
};

export default function GroupMembers() {
  const { user, isSuperAdmin } = useAuth();
  const { activeFleetId, activeFleet } = useFleet();
  const toast = useToast();

  const [members, setMembers] = useState([]);
  const [loading, setLoading] = useState(true);

  // Add member state
  const [showAdd, setShowAdd] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [searching, setSearching] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);
  const [addRole, setAddRole] = useState('fleet_staff');
  const [adding, setAdding] = useState(false);

  // Confirm modals
  const [removeConfirm, setRemoveConfirm] = useState(null);
  const [roleChange, setRoleChange] = useState(null);
  const [actionLoading, setActionLoading] = useState(null);

  useEffect(() => {
    if (activeFleetId) fetchMembers();
  }, [activeFleetId]);

  async function fetchMembers() {
    setLoading(true);
    const { data, error } = await supabase
      .from('bubatrent_booking_fleet_memberships')
      .select('*, bubatrent_booking_profiles(id, display_name, username, role)')
      .eq('fleet_group_id', activeFleetId)
      .order('created_at');
    if (error) console.error('Error fetching members:', error);
    setMembers(data || []);
    setLoading(false);
  }

  async function handleSearch(q) {
    setSearchQuery(q);
    if (q.length < 2) {
      setSearchResults([]);
      return;
    }
    setSearching(true);
    // Search profiles by display_name, username, or email
    const { data } = await supabase
      .from('bubatrent_booking_profiles')
      .select('id, display_name, username, role')
      .or(`display_name.ilike.%${q}%,username.ilike.%${q}%`)
      .in('role', ['admin', 'super_admin'])
      .limit(10);
    // Filter out already-members
    const memberIds = members.map((m) => m.user_id);
    setSearchResults((data || []).filter((u) => !memberIds.includes(u.id)));
    setSearching(false);
  }

  async function handleAddMember() {
    if (!selectedUser) return;
    setAdding(true);
    try {
      const { error } = await supabase.from('bubatrent_booking_fleet_memberships').insert({
        user_id: selectedUser.id,
        fleet_group_id: activeFleetId,
        role: addRole,
      });
      if (error) {
        if (error.code === '23505') toast.error('This user is already a member');
        else throw error;
      } else {
        // Audit log
        await supabase.from('bubatrent_booking_audit_logs').insert({
          admin_id: user.id,
          action: 'ADD_GROUP_MEMBER',
          resource_type: 'fleet_membership',
          resource_id: activeFleetId,
          details: { added_user: selectedUser.id, role: addRole, group: activeFleet?.name },
        });
        toast.success(
          `${selectedUser.display_name || selectedUser.username} added as ${ROLE_CONFIG[addRole].label}`
        );
        setShowAdd(false);
        setSelectedUser(null);
        setSearchQuery('');
        setSearchResults([]);
        await fetchMembers();
      }
    } catch (err) {
      toast.error(err.message);
    } finally {
      setAdding(false);
    }
  }

  async function handleRoleChange(membership, newRole) {
    setActionLoading(membership.id);
    try {
      const { error } = await supabase
        .from('bubatrent_booking_fleet_memberships')
        .update({ role: newRole })
        .eq('id', membership.id);
      if (error) throw error;

      await supabase.from('bubatrent_booking_audit_logs').insert({
        admin_id: user.id,
        action: 'CHANGE_MEMBER_ROLE',
        resource_type: 'fleet_membership',
        resource_id: membership.id,
        details: {
          target_user: membership.user_id,
          old_role: membership.role,
          new_role: newRole,
          group: activeFleet?.name,
        },
      });

      toast.success('Role updated');
      setRoleChange(null);
      await fetchMembers();
    } catch (err) {
      toast.error(err.message);
    } finally {
      setActionLoading(null);
    }
  }

  async function handleRemove(membership) {
    setActionLoading(membership.id);
    try {
      const { error } = await supabase
        .from('bubatrent_booking_fleet_memberships')
        .delete()
        .eq('id', membership.id);
      if (error) throw error;

      await supabase.from('bubatrent_booking_audit_logs').insert({
        admin_id: user.id,
        action: 'REMOVE_GROUP_MEMBER',
        resource_type: 'fleet_membership',
        resource_id: membership.id,
        details: { removed_user: membership.user_id, group: activeFleet?.name },
      });

      toast.success('Member removed');
      setRemoveConfirm(null);
      await fetchMembers();
    } catch (err) {
      toast.error(err.message);
    } finally {
      setActionLoading(null);
    }
  }

  const isFleetAdmin = members.some((m) => m.user_id === user?.id && m.role === 'fleet_admin');
  const canManage = isSuperAdmin || isFleetAdmin;

  return (
    <AdminLayout title={`Members — ${activeFleet?.name || 'Fleet'}`}>
      <p className="text-sm text-slate-400 mb-4">
        Manage who has access to this fleet group. Members can switch between groups they belong to.
      </p>

      {/* Add Member */}
      {canManage && (
        <div className="mb-6">
          {!showAdd ? (
            <button
              onClick={() => setShowAdd(true)}
              className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-medium bg-violet-500/20 text-violet-300 hover:bg-violet-500/30 border border-violet-500/30 transition-all"
            >
              <UserPlus className="w-4 h-4" /> Add Member
            </button>
          ) : (
            <div className="glass-card animate-fade-in">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-sm font-semibold text-white">
                  Add Member to {activeFleet?.name}
                </h3>
                <button
                  onClick={() => {
                    setShowAdd(false);
                    setSelectedUser(null);
                    setSearchQuery('');
                    setSearchResults([]);
                  }}
                  className="p-1 rounded-lg hover:bg-white/5 text-slate-500"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>

              {/* Search */}
              <div className="relative mb-3">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                <input
                  value={searchQuery}
                  onChange={(e) => handleSearch(e.target.value)}
                  className="input-field !pl-10"
                  placeholder="Search by name or email..."
                  autoFocus
                />
                {searching && (
                  <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 animate-spin" />
                )}
              </div>

              {/* Search results */}
              {searchResults.length > 0 && !selectedUser && (
                <div className="space-y-1 max-h-40 overflow-y-auto mb-3">
                  {searchResults.map((u) => (
                    <button
                      key={u.id}
                      onClick={() => {
                        setSelectedUser(u);
                        setSearchResults([]);
                      }}
                      className="w-full flex items-center gap-3 p-2.5 rounded-xl hover:bg-white/5 text-left transition-all"
                    >
                      <div className="w-8 h-8 rounded-full bg-violet-500/10 flex items-center justify-center text-xs font-bold text-violet-300">
                        {(u.display_name || u.username || '?')[0].toUpperCase()}
                      </div>
                      <div>
                        <p className="text-sm text-white font-medium">
                          {u.display_name || u.username}
                        </p>
                        <p className="text-[10px] text-slate-500">
                          {u.username} • {u.role}
                        </p>
                      </div>
                    </button>
                  ))}
                </div>
              )}

              {searchQuery.length >= 2 &&
                searchResults.length === 0 &&
                !searching &&
                !selectedUser && (
                  <p className="text-xs text-slate-500 mb-3">No matching admin users found</p>
                )}

              {/* Selected user */}
              {selectedUser && (
                <div className="bg-violet-500/5 border border-violet-500/20 rounded-xl p-3 mb-3">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <div className="w-8 h-8 rounded-full bg-violet-500/10 flex items-center justify-center text-xs font-bold text-violet-300">
                        {(selectedUser.display_name ||
                          selectedUser.username ||
                          '?')[0].toUpperCase()}
                      </div>
                      <div>
                        <p className="text-sm text-white font-medium">
                          {selectedUser.display_name || selectedUser.username}
                        </p>
                        <p className="text-[10px] text-slate-500">{selectedUser.username}</p>
                      </div>
                    </div>
                    <button
                      onClick={() => setSelectedUser(null)}
                      className="text-slate-500 hover:text-white"
                    >
                      <X className="w-3.5 h-3.5" />
                    </button>
                  </div>
                </div>
              )}

              {/* Role selector + Add button */}
              {selectedUser && (
                <div className="flex gap-2">
                  <select
                    value={addRole}
                    onChange={(e) => setAddRole(e.target.value)}
                    className="input-field flex-1"
                  >
                    <option value="fleet_admin">Fleet Admin</option>
                    <option value="fleet_staff">Staff</option>
                  </select>
                  <button
                    onClick={handleAddMember}
                    disabled={adding}
                    className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-medium bg-violet-500/20 text-violet-300 hover:bg-violet-500/30 border border-violet-500/30 transition-all disabled:opacity-50"
                  >
                    {adding ? (
                      <Loader2 className="w-4 h-4 animate-spin" />
                    ) : (
                      <UserPlus className="w-4 h-4" />
                    )}
                    Add
                  </button>
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* Members list */}
      {loading ? (
        <LoadingSpinner />
      ) : members.length === 0 ? (
        <EmptyState
          icon={Users}
          title="No members"
          description="This fleet group has no members yet."
        />
      ) : (
        <div className="space-y-2">
          {members.map((m) => {
            const profile = m.bubatrent_booking_profiles;
            const roleInfo = ROLE_CONFIG[m.role] || ROLE_CONFIG.fleet_staff;
            const RoleIcon = roleInfo.icon;
            const isCreator = activeFleet?.created_by === m.user_id;
            const isSelf = m.user_id === user?.id;

            return (
              <div key={m.id} className="glass-card flex items-center justify-between">
                <div className="flex items-center gap-3 min-w-0">
                  {/* Avatar */}
                  <div className="w-10 h-10 rounded-full bg-violet-500/10 flex items-center justify-center text-sm font-bold text-violet-300 shrink-0">
                    {(profile?.display_name || profile?.username || '?')[0].toUpperCase()}
                  </div>
                  <div className="min-w-0">
                    <div className="flex items-center gap-2 flex-wrap">
                      <p className="text-sm text-white font-medium truncate">
                        {profile?.display_name || profile?.username || 'Unknown'}
                      </p>
                      {isCreator && (
                        <span className="flex items-center gap-0.5 px-1.5 py-0.5 rounded text-[9px] bg-amber-500/20 text-amber-300 font-semibold">
                          <Crown className="w-2.5 h-2.5" /> Owner
                        </span>
                      )}
                      {isSelf && (
                        <span className="px-1.5 py-0.5 rounded text-[9px] bg-blue-500/20 text-blue-300 font-semibold">
                          You
                        </span>
                      )}
                    </div>
                    <p className="text-[10px] text-slate-500 truncate">{profile?.username}</p>
                  </div>
                </div>

                <div className="flex items-center gap-2 shrink-0">
                  {/* Role badge */}
                  <span
                    className={`flex items-center gap-1 px-2 py-1 rounded-lg text-[10px] font-semibold bg-${roleInfo.color}-500/10 text-${roleInfo.color}-400 border border-${roleInfo.color}-500/20`}
                  >
                    <RoleIcon className="w-3 h-3" /> {roleInfo.label}
                  </span>

                  {/* Actions — only if can manage and not self */}
                  {canManage && !isSelf && (
                    <div className="flex gap-1">
                      <button
                        onClick={() => setRoleChange(m)}
                        className="p-1.5 rounded-lg hover:bg-white/5 text-slate-500 hover:text-violet-400 transition-colors"
                        title="Change role"
                      >
                        <ChevronDown className="w-3.5 h-3.5" />
                      </button>
                      <button
                        onClick={() => setRemoveConfirm(m)}
                        className="p-1.5 rounded-lg hover:bg-red-500/10 text-slate-500 hover:text-red-400 transition-colors"
                        title="Remove member"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Role Change Modal */}
      {roleChange && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm"
          onClick={() => setRoleChange(null)}
        >
          <div
            className="glass-card w-full max-w-sm animate-fade-in"
            onClick={(e) => e.stopPropagation()}
          >
            <h3 className="text-lg font-semibold text-white mb-4">Change Role</h3>
            <p className="text-sm text-slate-400 mb-4">
              Change <strong>{roleChange.bubatrent_booking_profiles?.display_name}</strong>'s role
              in this group:
            </p>
            <div className="space-y-2 mb-4">
              {Object.entries(ROLE_CONFIG).map(([key, cfg]) => (
                <button
                  key={key}
                  onClick={() => handleRoleChange(roleChange, key)}
                  disabled={roleChange.role === key || actionLoading === roleChange.id}
                  className={`w-full flex items-center gap-3 p-3 rounded-xl border transition-all text-left ${
                    roleChange.role === key
                      ? 'bg-violet-500/10 border-violet-500/30 text-violet-300'
                      : 'bg-white/5 border-white/10 text-slate-300 hover:bg-white/10'
                  } disabled:opacity-50`}
                >
                  <cfg.icon className="w-4 h-4" />
                  <div>
                    <p className="text-sm font-medium">{cfg.label}</p>
                    <p className="text-[10px] text-slate-500">{cfg.desc}</p>
                  </div>
                  {roleChange.role === key && (
                    <span className="ml-auto text-[10px] text-violet-400">Current</span>
                  )}
                </button>
              ))}
            </div>
            <button onClick={() => setRoleChange(null)} className="btn-secondary w-full">
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Remove Confirmation Modal */}
      {removeConfirm && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm"
          onClick={() => setRemoveConfirm(null)}
        >
          <div
            className="glass-card w-full max-w-sm animate-fade-in"
            onClick={(e) => e.stopPropagation()}
          >
            <h3 className="text-lg font-semibold text-white mb-2">Remove Member</h3>
            <p className="text-sm text-slate-400 mb-4">
              Are you sure you want to remove{' '}
              <strong>{removeConfirm.bubatrent_booking_profiles?.display_name}</strong> from this
              group? They will lose access to all group data.
            </p>
            <div className="flex gap-3">
              <button onClick={() => setRemoveConfirm(null)} className="btn-secondary flex-1">
                Cancel
              </button>
              <button
                onClick={() => handleRemove(removeConfirm)}
                disabled={actionLoading === removeConfirm.id}
                className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-sm font-medium bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/20 transition-all disabled:opacity-50"
              >
                {actionLoading === removeConfirm.id ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : (
                  <Trash2 className="w-4 h-4" />
                )}
                Remove
              </button>
            </div>
          </div>
        </div>
      )}
    </AdminLayout>
  );
}

